import { PremiumActions } from '@app/actions/premium';
import { browser_api } from '@app/browser_api';
import { featureStore } from '@app/features/list';
import { Feature } from '@app/features/types/Feature';
import { ShowMidRollMessage } from '@app/messages/premium';
import { getLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { logger } from '@utils/logger';

export async function showMidRoll() {
  try {
    logger.info('youboost:midpoint');
    const { hasPremium } = await getLocalStorageData(
      LocalStorageKey.HasPremium,
    );
    const { featuresList } = await featureStore.getSnapshotAsync();
    const isVideoMidRollEnabled = Boolean(
      featuresList?.[Feature.MidpointMedia],
    );

    if (hasPremium || !isVideoMidRollEnabled) {
      return;
    }

    const tabs = await browser_api.tabs.query({
      active: true,
      currentWindow: true,
      url: ['*://*.youtube.com/*'],
    });

    await Promise.all(
      tabs.map((tab) => {
        if (tab.id) {
          return browser_api.tabs.sendMessage<ShowMidRollMessage>(tab.id, {
            action: PremiumActions.ShowMidpoint,
          });
        }
        return null;
      }),
    );
  } catch (error) {
    logger.error('Error handling midpoint alarm:', error);
  }
}
