import { getPACData } from '@background/pac-script/utils/getPACData';
import { enableProxy } from '../proxyControl';
import { logger } from '@utils/logger';

export async function updatePacScriptToLitePAC(): Promise<void> {
  logger.info('updatePacScriptToLitePAC');
  await getPACData({
    shouldRefetch: true,
    isLitePACInner: true,
  });
  await enableProxy();
}
