import { getChromePremiumAlarm, PremiumAlarms } from '@app/alarms/premium';
import { browser_api } from '@app/browser_api';
import { getMetaApiData } from '@utils/metaApiData';
import { logger } from '@utils/logger';
import { updateProxyPremiumDataAlarm } from './updateProxyPremiumDataAlarm';

export async function createOrUpdatePremiumProxyDataAlarm(): Promise<void> {
  try {
    const { proxyUpdatePeriod } = await getMetaApiData();

    const existingUpdateProxyPremiumDataAlarm = await getChromePremiumAlarm(
      PremiumAlarms.UpdateProxyPremiumData,
    );

    if (existingUpdateProxyPremiumDataAlarm) {
      await browser_api.alarms.clear(PremiumAlarms.UpdateProxyPremiumData);
    }

    browser_api.alarms.create(PremiumAlarms.UpdateProxyPremiumData, {
      periodInMinutes: proxyUpdatePeriod,
      delayInMinutes: proxyUpdatePeriod,
    });

    // We need to start it immediately, alarms.create with 0 delay is not working fo Firefox.
    void updateProxyPremiumDataAlarm();
  } catch (error) {
    logger.error('createOrUpdatePremiumProxyDataAlarm: error', error);
  }
}
