import { browser_api } from '@app/browser_api';
import { logger } from '@utils/logger';

import { Alarms, getChromeAlarm } from '@app/alarms/shared';
import { featureStore } from '@app/features/list';

export async function createOrUpdateFeaturesDataAlarm(): Promise<void> {
  try {
    const featuresDataAlarmPeriod = process.env.FEATURES_DATA_ALARM_PERIOD
      ? parseInt(process.env.FEATURES_DATA_ALARM_PERIOD, 10)
      : 10;

    const existingUpdateFeaturesDataAlarm = await getChromeAlarm(
      Alarms.UpdateFeaturesData,
    );

    if (existingUpdateFeaturesDataAlarm) {
      await browser_api.alarms.clear(Alarms.UpdateFeaturesData);
    }

    browser_api.alarms.create(Alarms.UpdateFeaturesData, {
      periodInMinutes: featuresDataAlarmPeriod,
      delayInMinutes: featuresDataAlarmPeriod,
    });

    await featureStore.init();
  } catch (error) {
    logger.error('createOrUpdateFeaturesDataAlarm: error', error);
  }
}
