import { browser_api } from '@app/browser_api';
import { giftAlarmHandlerListener } from '../giftAlarmHandlerListener';

export const removeGiftAlarmHandler = () => {
  if (browser_api.alarms.onAlarm.hasListener(giftAlarmHandlerListener)) {
    browser_api.alarms.onAlarm.removeListener(giftAlarmHandlerListener);
  }
};
