import { Alarms } from '@app/alarms/shared';
import { browser_api } from '@app/browser_api';
import { setLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { disableProxy } from '@background/network/proxy/proxyControl';
import { logger } from '@utils/logger';

const FREE_USAGE_TIME_IN_SECONDS = process.env.FREE_USAGE_TIME_IN_SECONDS;

export const onFreeUsageSecondsLeftChanged = async (
  changes: Record<string, browser_api.Storage.StorageChange>,
) => {
  try {
    logger.info('shared:onFreeUsageSecondsLeftChanged');

    const freeUsageSecondsLeftChange =
      changes[LocalStorageKey.FreeUsageSecondsLeft]?.newValue;
    const freeUsageSecondsLeftOldValue =
      changes[LocalStorageKey.FreeUsageSecondsLeft]?.oldValue;

    // Условие ниже нужно, чтобы избежать проблем с гонкой листенеров алармов.
    // Иногда параллельно с хэндлером updateFreeUsageSeconds срабатывал хэндлер
    // на сброс секунд resetFreeUsageAlarm.
    // Но т.к. первый хэндлер получал значение стора до сброса,
    // то он и перезаписывал потом это значение минус 1 - т.е. сброс секунд просто не работал
    if (
      freeUsageSecondsLeftOldValue === Number(FREE_USAGE_TIME_IN_SECONDS) &&
      Number(freeUsageSecondsLeftOldValue) -
        Number(freeUsageSecondsLeftChange) >
        1
    ) {
      await setLocalStorageData({
        [LocalStorageKey.FreeUsageSecondsLeft]: Number(
          freeUsageSecondsLeftOldValue,
        ),
      });
      return;
    }

    if (
      typeof freeUsageSecondsLeftChange !== 'number' ||
      freeUsageSecondsLeftChange === 0
    ) {
      await browser_api.alarms.clear(Alarms.FreeUsage);
      disableProxy();
      return;
    }

    if (freeUsageSecondsLeftChange === Number(FREE_USAGE_TIME_IN_SECONDS)) {
      const freeUsageAlarm = await browser_api.alarms.get(Alarms.FreeUsage);
      if (freeUsageAlarm) {
        return;
      }
      browser_api.alarms.create(Alarms.FreeUsage, {
        periodInMinutes: 1 / 60, // 1 second
      });
    }
  } catch (error) {
    console.error('onFreeUsageSecondsLeftChanged error', error);
  }
};
