import {
  PACDataGeneral,
  PACPremiumData,
} from '@app/storage/local/types/persistentTypes';

export function isPACPremiumData(
  data: PACDataGeneral,
): data is PACPremiumData {
  if (!data || typeof data !== 'object') {
    return false;
  }

  const pacData = data as PACPremiumData;

  if (process.env.EXTENSION_CODE === 'vrubel') {
    return pacData.premium !== undefined;
  }

  return pacData.premium !== undefined && pacData.allInternet !== undefined;
}
