import { setLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { getDeviceIP } from '@app/storage/utils/getDeviceIP';
import { getDeviceId } from '@app/storage/utils/getDeviceId';
import { getMetaApiData } from '@utils/metaApiData';
import { setupProxyAuth } from '../proxyAuth';
import { ProxyFailReason } from '../types/ProxyData';
import {
  configureProxy,
  onProxySuccess,
  processPACData,
  onProxyFailed,
} from './utils';
import { getProxyDataWithStatus } from './utils/getProxyDataWithStatus';
import { updatePacScript } from '@background/pac-script/updatePacScript';
import { getPACData } from '@background/pac-script/utils/getPACData';
import { logger } from '@utils/logger';
import { checkProxyAvailability } from '@api/checkProxyAvailability';

export async function enableProxy({
  onFail,
  onFailReason,
}: { onFail?: boolean; onFailReason?: ProxyFailReason } = {}): Promise<void> {
  try {
    logger.info(
      'enableProxy: start',
      JSON.stringify({ onFail, onFailReason }, null, 2),
    );
    // 1. Инициализация
    await setLocalStorageData({ [LocalStorageKey.CurrentState]: 'connecting' });

    // 2. Получение метаданных
    const [{ apiBaseUrl }, deviceId, deviceIp] = await Promise.all([
      getMetaApiData(),
      getDeviceId(),
      getDeviceIP(),
    ]);

    // 3. Получение данных прокси
    const proxyData = await getProxyDataWithStatus({
      apiBaseUrl,
      deviceId,
      deviceIp,
      onFail,
      onFailReason,
    });

    logger.info(`enableProxy: proxyData:${JSON.stringify(proxyData, null, 2)}`);
    logger.info(`enableProxy: onFail:${onFail}`);
    logger.info(`enableProxy: onFailReason:${onFailReason}`);

    logger.info('enableProxy:proxyData', JSON.stringify(proxyData, null, 2));

    // 4. Настройка аутентификации
    await setupProxyAuth(proxyData.data.proxies);

    // 5. Сохранение данных
    await setLocalStorageData({
      [LocalStorageKey.ProxyData]: proxyData,
    });

    // 6. Получение PAC данных
    await updatePacScript();
    const pacData = await getPACData({});

    // 7. Обработка PAC данных
    const proxyConfig = await processPACData(pacData, proxyData.data.proxies);

    // 8. Настройка прокси
    await configureProxy(proxyConfig);

    // 9. Проверка актуальности прокси
    const availabilityResult = await checkProxyAvailability();

    if (!availabilityResult.isProxyAvailable) {
      const onFailReason = availabilityResult.onFailReason;
      // 10.1 Обработка нерабочей прокси
      logger.info(`enableProxyOnFailAlarm: onFailReason:${onFailReason}`);
      const shouldRetry = await onProxyFailed();
      if (shouldRetry) {
        // 11 Рекурсивная попытка с новым прокси
        await enableProxy({
          onFail: true,
          onFailReason,
        });
      }
      return;
    }

    // 10.2 Обработка рабочей прокси
    logger.info(`enableProxyOnFailAlarm: isProxyAvailable:true`);
    await onProxySuccess();
    logger.info('enableProxy:success');
  } catch (error) {
    logger.error('enableProxy: error loading configuration', error);
    await setLocalStorageData({ currentState: 'error' });
  }
}
