import { Alarms } from '@app/alarms/shared';
import { browser_api } from '@app/browser_api';
import { getPACData } from '@background/pac-script/utils/getPACData';
import { enableProxy } from '../proxyControl';
import { logger } from '@utils/logger';
export async function updatePacScriptToFullPAC(): Promise<void> {
  logger.info('updatePacScriptToFullPAC');
  await getPACData({ shouldRefetch: true, isLitePACInner: false });
  await enableProxy();

  browser_api.alarms.create(Alarms.RestoreLitePAC, {
    delayInMinutes: process.env.RESTORE_LITE_PAC_DELAY_MINUTES
      ? parseInt(process.env.RESTORE_LITE_PAC_DELAY_MINUTES)
      : 24 * 60, // 24 hours
  });
}
