import { Actions } from '@app/actions/shared';
import { featureStore } from '@app/features/list';
import { getMetaApiData } from '@utils/metaApiData';
import {
  deleteLocalStorageData,
  getLocalStorageData,
} from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import dayjs from 'dayjs';
import { Feature } from '@app/features/types/Feature';
import {
  initGiftAlarms,
  setupGiftAlarmHandler,
  removeGiftAlarmHandler,
} from '@background/gifts/alarms';
import { MessageHandler } from '@app/infrastructure/types';
import { isGiftAdvertisingAvailable } from '@background/gifts/utils';
import { setupGiftMessageHandler } from '../setupGiftMessageHandler';
import { unregisterGiftMessageHandler } from '../unregisterGiftMessageHandler';

export const initGiftsScriptReadyHandler: MessageHandler<
  Actions.InitGiftsScriptReady
> = async () => {
  const { featuresList } = await featureStore.getSnapshotAsync();
  const { giftsAvailableDates } = await getMetaApiData();
  const { giftRefusedUntil } = await getLocalStorageData(
    LocalStorageKey.GiftRefusedUntil,
  );
  const now = dayjs();
  const isRefused = Boolean(
    giftRefusedUntil && dayjs(giftRefusedUntil).isAfter(now),
  );

  if (giftRefusedUntil && dayjs(giftRefusedUntil).isBefore(now)) {
    await deleteLocalStorageData(LocalStorageKey.GiftRefusedUntil);
  }

  // We need to clean up all listeners if gift advertising is disabled or expired or not started yet
  if (
    featuresList?.[Feature.Gifts] &&
    isGiftAdvertisingAvailable(giftsAvailableDates) &&
    !isRefused
  ) {
    setupGiftAlarmHandler();
    setupGiftMessageHandler();
    initGiftAlarms();
  } else {
    removeGiftAlarmHandler();
    unregisterGiftMessageHandler();
  }
};
