import { LogsStorageKey } from '../types/logsTypes';
import { isQuotaError } from './isQuotaError';
import { browser_api } from '@app/browser_api';

export async function handleStorageQuotaError(error: unknown): Promise<void> {
  if (!isQuotaError(error)) {
    return;
  }

  try {
    await browser_api.storage.local.remove(LogsStorageKey.Logs);
  } catch (nestedError) {
    console.error(
      'handleStorageQuotaError: failed to remove logs',
      nestedError,
    );
  }
}
