import {
  getLocalStorageData,
  setLocalStorageData,
} from '@app/storage/local/shared';
import { PACPremiumData } from '@app/storage/local/types/persistentTypes';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import type {
  PremiumProxies,
  PremiumProxyData,
  ProxyConfig,
} from '@background/network/proxy/types/ProxyData';
import { ProxyModeType } from '@app/storage/local/types/constantTypes';
import { isPACPremiumData } from '@background/pac-script/utils/isPACPremiumData';
import { isPACData } from '@background/pac-script/utils/isPACData';

type ExtractPremiumProxiesResult = {
  default: PremiumProxyData;
  vpn: PremiumProxyData;
};

export function extractPremiumProxies(
  proxies: PremiumProxies,
): [PremiumProxyData, PremiumProxyData] {
  const result = proxies.reduce<ExtractPremiumProxiesResult>((acc, proxy) => {
    if (proxy.proxy_type === 'default') {
      acc.default = proxy;
    } else if (proxy.proxy_type === 'vpn') {
      acc.vpn = proxy;
    }
    return acc;
  }, {} as ExtractPremiumProxiesResult);

  return [result.default, result.vpn];
}

export function processPremiumPACData(
  pacData: PACPremiumData,
  proxies: PremiumProxies,
  isAllInternetProxy?: boolean,
  currentLocale?: string,
  youboostAllInternetMode?: ProxyModeType,
): ProxyConfig {
  if (!proxies.length) {
    throw new Error('Proxy data is missing');
  }
  const [premiumProxy, allInternetProxy] = extractPremiumProxies(proxies);

  let pacString = pacData.premium;
  let vpnProxyHost: string | undefined;
  let vpnProxyPort: number | undefined;

  const mode: ProxyModeType =
    youboostAllInternetMode ?? (currentLocale === 'ru' ? 'smart' : 'direct');

  if (isAllInternetProxy) {
    pacString = pacData.allInternet;
    vpnProxyHost = allInternetProxy.host;
    vpnProxyPort = allInternetProxy.port;
    if (pacData?.fullAllInternet && mode === 'direct') {
      pacString = pacData.fullAllInternet;
    } else {
      pacString = pacData.allInternet;
    }
  }

  return {
    pacString,
    proxyHost: premiumProxy.host,
    proxyPort: premiumProxy.port,
    vpnProxyHost,
    vpnProxyPort,
    shouldDecompress: true,
  };
}

export function processFreePACData(
  pacData: any,
  proxies: PremiumProxies,
): ProxyConfig {
  const proxy = proxies?.[0];
  if (!proxy) {
    throw new Error('Proxy data is missing');
  }

  return {
    pacString: pacData.free,
    proxyHost: proxy.host,
    proxyPort: proxy.port,
    shouldDecompress: false,
  };
}

export async function processPACData(
  pacData: any,
  proxies: PremiumProxies,
): Promise<ProxyConfig> {
  const {
    userId,
    hasPremium,
    isAllInternetProxy,
    currentLocale,
    youboostAllInternetMode,
  } = await getLocalStorageData([
    LocalStorageKey.UserId,
    LocalStorageKey.HasPremium,
    LocalStorageKey.IsAllInternetProxy,
    LocalStorageKey.CurrentLocale,
    LocalStorageKey.YouboostAllInternetMode,
  ]);

  if (isPACPremiumData(pacData) && userId && hasPremium) {
    return processPremiumPACData(
      pacData,
      proxies,
      isAllInternetProxy,
      currentLocale,
      youboostAllInternetMode,
    );
  } else if (isPACData(pacData)) {
    return processFreePACData(pacData, proxies);
  } else {
    await setLocalStorageData({ currentState: 'error' });
    throw new Error('Invalid PAC data format');
  }
}
