import { AuthDetails, AuthResponse } from '@background/network/proxy/types';
import { getLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { featureStore } from '@app/features/list';
import { Feature } from '@app/features/types/Feature';
import { PingPongService } from '@background/services/pingPongService';
import { logger } from '@utils/logger';

const pingPong = new PingPongService();

const CACHE_CONTROL_HEADERS = [
  { name: 'Cache-Control', value: 'no-cache, no-store, must-revalidate' },
  { name: 'Pragma', value: 'no-cache' },
  { name: 'Expires', value: '0' },
] as const;

export async function handleProxyAuth(
  details: AuthDetails,
): Promise<AuthResponse> {
  const { proxyCredential, targetState } = await getLocalStorageData([
    LocalStorageKey.ProxyCredential,
    LocalStorageKey.TargetState,
  ]);

  const { featuresList } = await featureStore.getSnapshotAsync();
  const isPingPongEnabled = featuresList[Feature.ServiceWorkerPingPong];

  if (isPingPongEnabled) {
    await pingPong.init();
  }

  // Early return for non-proxy requests
  if (!details.isProxy) {
    return { cancel: false };
  }

  if (isPingPongEnabled && !pingPong.isInitialized) {
    logger.error('handleProxyAuth: PingPongService is not initialized');

    return { cancel: true };
  }

  if (targetState !== 'connected') {
    logger.error('handleProxyAuth: Current state is not connected');

    return { cancel: true };
  }

  if (!proxyCredential) {
    logger.error('handleProxyAuth: No proxy credential');

    return { cancel: true };
  }

  const { host, port } = details.challenger;
  const proxyKey = `${host}:${port}`;
  const credentials = proxyCredential[proxyKey];

  if (!credentials?.userName || !credentials?.password) {
    logger.error(`handleProxyAuth: No credentials found for proxy ${proxyKey}`);
    return { cancel: true };
  }

  return {
    authCredentials: {
      username: credentials.userName,
      password: credentials.password,
    },
    responseHeaders: [...CACHE_CONTROL_HEADERS],
  };
}
