import { createOrUpdatePremiumProxyDataAlarm } from '@background/alarmHandlers/createOrUpdatePremiumProxyDataAlarm';
import { logger } from '@utils/logger';

export async function onStartupListener() {
  try {
    await createOrUpdatePremiumProxyDataAlarm();
  } catch (error) {
    logger.error('onStartupListener: error', error);
  }
}
