import { Actions } from '@app/actions/shared';
import { logger } from '@utils/logger';
import { sendMessageToYoutubeTabs } from '@background/utils/sendMessageToYoutubeTabs';
import { MessageHandler } from '@app/infrastructure/types';

export const hideAllToastsByType: MessageHandler<
  Actions.HideAllToastsByType
> = async (message) => {
  try {
    logger.info('runtimeOnMessageListener:HideAllToastsByType');
    await sendMessageToYoutubeTabs(Actions.HideAllToastsByType, {
      type: message.payload.type,
    });
  } catch (error) {
    logger.error('HideAllToastsByType: error', error);
  }
};
