import { browser_api } from '@app/browser_api';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import type { WebRequest } from 'webextension-polyfill';
import { Alarms } from '@app/alarms/shared';
import {
  deleteLocalStorageData,
  getLocalStorageData,
} from '@app/storage/local/shared';

import { isTinyImgError } from '../isTinyImgError';
import { isTargetWebRequestError } from '../isTargetWebRequestError';
import { getIsLitePACEnabled } from '@background/utils/getIsLitePACEnabled';
import { enableProxy } from '@background/network/proxy/proxyControl';
import { ProxyFailReason } from '@background/network/proxy/types/ProxyData';
import {
  ERROR_THRESHOLD,
  WEB_REQUEST_URLS,
} from '@background/network/monitor/constants';
import { addProxyError } from '@background/network/monitor/addProxyError';
import { logger } from '@utils/logger';

export const networkConnectionMonitorListener = createWebRequestErrorHandler();

export function initNetworkConnectionMonitor(): void {
  // Listener for network errors specifically targeting YouTube
  if (
    browser_api.webRequest.onErrorOccurred.hasListener(
      networkConnectionMonitorListener,
    )
  ) {
    browser_api.webRequest.onErrorOccurred.removeListener(
      networkConnectionMonitorListener,
    );
  }

  browser_api.webRequest.onErrorOccurred.addListener(
    networkConnectionMonitorListener,
    {
      urls: WEB_REQUEST_URLS,
    },
  );
}

function createWebRequestErrorHandler() {
  return async (details: WebRequest.OnErrorOccurredDetailsType) => {
    const { currentState } = await getLocalStorageData(
      LocalStorageKey.CurrentState,
    );

    if (currentState !== 'connected') return;
    const isTinyimgError = isTinyImgError(details);
    if (isTinyimgError) {
      logger.info('tinyimg error occurred');

      const isLitePACEnabled = await getIsLitePACEnabled();
      logger.info('isLitePACEnabled', isLitePACEnabled);
      if (!isLitePACEnabled) return;

      const isAlarmExists = await browser_api.alarms.get(
        Alarms.UpdatePacScriptToFullPAC,
      );

      if (isAlarmExists) {
        await browser_api.alarms.clear(Alarms.UpdatePacScriptToFullPAC);
      }

      browser_api.alarms.create(Alarms.UpdatePacScriptToFullPAC, {
        delayInMinutes: 0,
      });
    }

    const isTargetRequest = isTargetWebRequestError(details);
    if (!isTargetRequest) return;
    const errorCount = await addProxyError(details);
    if (errorCount < ERROR_THRESHOLD) return;
    console.warn(`Proxy failed: ${errorCount} errors detected`);
    await deleteLocalStorageData(LocalStorageKey.ProxyErrorLog);
    // Сменить прокси
    await enableProxy({
      onFail: true,
      onFailReason: ProxyFailReason.ProxyNotAvailable,
    });
  };
}
