import { Actions } from '@app/actions/shared';
import { browser_api } from '@app/browser_api';
import {
  CookieKey,
  getCookieData,
  setCookieData,
} from '@app/storage/cookies/shared';
import {
  getLocalStorageData,
  setLocalStorageData,
} from '@app/storage/local/shared';
import {
  type ConnectionState,
  type PaymentStatus,
} from '@app/storage/local/types/persistentTypes';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { onIsConnectionButtonDisabledChanged } from '@background/localStorageHandlers/onIsConnectionButtonDisabledChanged';
import { onFeatureStoreChanged } from '@background/localStorageHandlers/onFeatureStoreChanged';
import { onHasPremiumChanged } from '@background/localStorageHandlers/onHasPremiumChanged';
import { onIsAllInternetProxyChanged } from '@background/localStorageHandlers/onIsAllInternetProxyChanged';
import { onOnboardingScreenStatusChanged } from '@background/localStorageHandlers/onOnboardingScreenStatusChanged';
import { onTargetStateChanged } from '@background/localStorageHandlers/onTargetStateChanged';
import { sendMessageToYoutubeTabs } from '@background/utils/sendMessageToYoutubeTabs';
import { logger } from '@utils/logger';
import { getMetaApiData } from '@utils/metaApiData';
import { onMetaApiDataChanged } from '@background/localStorageHandlers/onMetaApiDataChanged';
import { onStatusChanged } from '@background/localStorageHandlers/onStatusChanged';
import { onFreeUsageSecondsLeftChanged } from '@background/localStorageHandlers/onFreeUsageSecondsLeftChanged';
import { onCurrentStateChanged } from '@background/localStorageHandlers/onCurrentStateChanged';
import { languageChangeListenerHandler } from '@app/i18n/utils';
import { navigateToExtensionPage } from '@background/utils/navigateToExtensionPage';
import { RoutePath } from '@popup/project/peremen/routes/types/RoutePath';
import { messageDispatcher } from '@app/infrastructure/messageDispatcher';

export async function storageOnChangedListener(
  changes: Record<string, browser_api.Storage.StorageChange>,
  areaName: string,
) {
  if (areaName === 'local' && changes[LocalStorageKey.Status]) {
    logger.info('shared:storageOnChangedListener', 'Status');
    const oldStatus = changes[LocalStorageKey.Status]?.oldValue;
    const newStatus = changes[LocalStorageKey.Status]?.newValue;

    if (oldStatus !== newStatus) {
      await sendMessageToYoutubeTabs(Actions.UserStatusChanged, {
        status: newStatus as PaymentStatus,
      });

      // TODO EXT-41 убрать костыль проверки расширения из shared ( process.env.EXTENSION_CODE )
      if (process.env.EXTENSION_CODE === 'peremen') {
        if (newStatus === 'Paid') {
          await navigateToExtensionPage(
            RoutePath.SuccessfulPremiumSubscription,
          );
        }
      } else {
        await messageDispatcher.send({
          action: Actions.UserStatusChanged,
          payload: { status: newStatus as PaymentStatus },
        });
      }
      await onStatusChanged(newStatus as PaymentStatus);
    }
  }

  if (areaName === 'local' && changes[LocalStorageKey.CurrentState]) {
    logger.info('shared:storageOnChangedListener', 'CurrentState');
    const oldCurrentState = changes[LocalStorageKey.CurrentState]?.oldValue;
    const newCurrentState = changes[LocalStorageKey.CurrentState]?.newValue;

    if (oldCurrentState !== newCurrentState) {
      sendMessageToYoutubeTabs(Actions.ConnectionStateChanged, {
        connectionState: newCurrentState as ConnectionState,
      });

      onCurrentStateChanged(newCurrentState as ConnectionState);

      // We need to disconnect the proxy when it's in error state
      if (newCurrentState === 'error') {
        await setLocalStorageData({
          [LocalStorageKey.TargetState]: 'disconnected',
        });
      }
    }
  }

  if (areaName === 'local' && changes[LocalStorageKey.ConfigsBaseUrl]) {
    logger.info('shared:storageOnChangedListener', 'ConfigsBaseUrl');
    const oldConfigsBaseUrl = changes[LocalStorageKey.ConfigsBaseUrl]?.oldValue;
    const newConfigsBaseUrl = changes[LocalStorageKey.ConfigsBaseUrl]?.newValue;
    if (oldConfigsBaseUrl !== newConfigsBaseUrl) {
      sendMessageToYoutubeTabs(Actions.ConfigsBaseUrl, {
        configsBaseUrl: newConfigsBaseUrl as string,
      });
    }
  }

  // We need to update the userId in cookies when it changes in local storage
  if (areaName === 'local' && changes[LocalStorageKey.UserId]) {
    logger.info('shared:storageOnChangedListener', 'UserId');
    const { cookieDomain } = await getMetaApiData();

    const newUserId = changes[LocalStorageKey.UserId]?.newValue;
    const oldUserId = changes[LocalStorageKey.UserId]?.oldValue;

    if (!cookieDomain) {
      throw new Error('No cookie domain provided');
    }

    if (newUserId !== oldUserId) {
      const { userId: cookieUserId } = await getCookieData(
        CookieKey.UserId,
        cookieDomain,
      );

      if (typeof newUserId === 'string' && newUserId !== cookieUserId) {
        await setCookieData(
          {
            [CookieKey.UserId]: newUserId,
          },
          cookieDomain,
        );
      }
    }
  }

  if (areaName === 'local' && changes[LocalStorageKey.DeviceId]) {
    logger.info('shared:storageOnChangedListener', 'DeviceId');
    const { cookieDomain } = await getMetaApiData();

    const newDeviceId = changes[LocalStorageKey.DeviceId].newValue;
    const oldDeviceId = changes[LocalStorageKey.DeviceId].oldValue;

    if (!cookieDomain) {
      throw new Error('No cookie domain provided');
    }

    if (newDeviceId !== oldDeviceId) {
      const { deviceId: cookieDeviceId } = await getCookieData(
        CookieKey.DeviceId,
        cookieDomain,
      );

      if (typeof newDeviceId === 'string' && newDeviceId !== cookieDeviceId) {
        await setCookieData(
          {
            [CookieKey.DeviceId]: newDeviceId,
          },
          cookieDomain,
        );
      }
    }
  }

  if (areaName === 'local' && changes[LocalStorageKey.IsInitialized]) {
    logger.info('shared:storageOnChangedListener', 'IsInitialized');
    const oldIsInitialized = changes[LocalStorageKey.IsInitialized]?.oldValue;
    const newIsInitialized = changes[LocalStorageKey.IsInitialized]?.newValue;

    if (oldIsInitialized !== newIsInitialized) {
      const isInitialized = newIsInitialized;

      if (isInitialized) {
        await onOnboardingScreenStatusChanged();
      }
    }
  }

  if (areaName === 'local' && changes[LocalStorageKey.OnboardingScreenStatus]) {
    logger.info('shared:storageOnChangedListener', 'OnboardingScreenStatus');
    const oldOnboardingScreenStatus =
      changes[LocalStorageKey.OnboardingScreenStatus]?.oldValue;
    const newOnboardingScreenStatus =
      changes[LocalStorageKey.OnboardingScreenStatus]?.newValue;

    if (oldOnboardingScreenStatus !== newOnboardingScreenStatus) {
      // We need to reinit all listeners after login
      if (newOnboardingScreenStatus === 'done') {
        await onOnboardingScreenStatusChanged();
      }
    }
  }

  if (areaName === 'local' && changes[LocalStorageKey.HasPremium]) {
    logger.info('shared:storageOnChangedListener', 'HasPremium');
    const oldHasPremium = changes[LocalStorageKey.HasPremium]?.oldValue;
    const newHasPremium = changes[LocalStorageKey.HasPremium]?.newValue;

    if (oldHasPremium !== newHasPremium) {
      await onHasPremiumChanged();
    }
  }

  if (areaName === 'local' && changes[LocalStorageKey.TargetState]) {
    logger.info('shared:storageOnChangedListener', 'TargetState');
    const oldTargetState = changes[LocalStorageKey.TargetState]?.oldValue;
    const newTargetState = changes[LocalStorageKey.TargetState]?.newValue;

    if (oldTargetState !== newTargetState) {
      await onTargetStateChanged();
    }
  }

  // TODO EXT-41 убрать костыль проверки расширения из shared ( process.env.EXTENSION_CODE )
  if (
    areaName === 'local' &&
    changes[LocalStorageKey.IsAllInternetProxy] &&
    process.env.EXTENSION_CODE !== 'peremen'
  ) {
    logger.info('shared:storageOnChangedListener', 'IsAllInternetProxy');
    const oldIsAllInternetProxy =
      changes[LocalStorageKey.IsAllInternetProxy]?.oldValue;
    const newIsAllInternetProxy =
      changes[LocalStorageKey.IsAllInternetProxy]?.newValue;

    if (oldIsAllInternetProxy !== newIsAllInternetProxy) {
      await onIsAllInternetProxyChanged();
    }
  }

  if (areaName === 'local' && changes[LocalStorageKey.FeatureStore]) {
    logger.info('shared:storageOnChangedListener', 'FeatureStore');
    await onFeatureStoreChanged(changes);
  }

  if (
    areaName === 'local' &&
    changes[LocalStorageKey.IsConnectionButtonDisabled]
  ) {
    logger.info(
      'shared:storageOnChangedListener',
      'IsConnectionButtonDisabled',
    );
    const oldIsConnectionButtonDisabled =
      changes[LocalStorageKey.IsConnectionButtonDisabled]?.oldValue;
    const newIsConnectionButtonDisabled =
      changes[LocalStorageKey.IsConnectionButtonDisabled]?.newValue;

    if (oldIsConnectionButtonDisabled !== newIsConnectionButtonDisabled) {
      onIsConnectionButtonDisabledChanged(changes);
    }
  }

  if (areaName === 'local' && changes[LocalStorageKey.MetaApiData]) {
    logger.info('shared:storageOnChangedListener', 'MetaApiData');
    await onMetaApiDataChanged(changes);
  }

  if (areaName === 'local' && changes[LocalStorageKey.FreeUsageSecondsLeft]) {
    logger.info('shared:storageOnChangedListener', 'FreeUsageSecondsLeft');
    await onFreeUsageSecondsLeftChanged(changes);
  }

  if (areaName === 'local' && changes[LocalStorageKey.CurrentLocale]) {
    const oldLanguage = changes[LocalStorageKey.CurrentLocale].oldValue;
    const newLanguage = changes[LocalStorageKey.CurrentLocale].newValue;
    if (!oldLanguage && !!newLanguage) {
      const { youboostAllInternetMode } = await getLocalStorageData(
        LocalStorageKey.YouboostAllInternetMode,
      );
      if (!youboostAllInternetMode) {
        await setLocalStorageData({
          [LocalStorageKey.YouboostAllInternetMode]:
            newLanguage === 'ru' ? 'smart' : 'direct',
        });
      }
    }

    await languageChangeListenerHandler(newLanguage);
  }
}
