import { PremiumAlarms } from '@app/alarms/premium';
import { browser_api } from '@app/browser_api';
import { logger } from '@utils/logger';
import {
  PremiumActionResponseMap,
  PremiumMessage,
} from '@app/messages/premium';
import { PremiumActions } from '@app/actions/premium';
import { ALARM_MINIMUM_PERIOD_IN_MINUTES } from '@app/alarms/constants';

export const premiumCanceledHandler = async (
  _message: Extract<PremiumMessage, { action: PremiumActions.PremiumCanceled }>,
): Promise<PremiumActionResponseMap[PremiumActions.PremiumCanceled]> => {
  logger.info('youboost:Premium canceled');
  browser_api.alarms.create(PremiumAlarms.PremiumCanceled, {
    periodInMinutes: ALARM_MINIMUM_PERIOD_IN_MINUTES,
  });
};
