import { Actions } from '@app/actions/shared';
import { type FailedVideoOpenMessage } from '@app/messages/shared';
import { logger } from '@utils/logger';
import { browser_api } from '@app/browser_api';
import { MessageHandler } from '@app/infrastructure/types';

export const failedVideoOpen: MessageHandler<Actions.FailedVideoOpen> = async (
  message,
  { tab },
) => {
  try {
    if (!tab?.id) return;
    logger.info('runtimeOnMessageListener:Failed video open');
    browser_api.tabs.onUpdated.addListener(
      async function listener(tabIdUpdated, changeInfo) {
        if (tabIdUpdated === tab.id && changeInfo.status === 'complete') {
          await browser_api.tabs.sendMessage<FailedVideoOpenMessage>(
            tabIdUpdated,
            message,
          );
          browser_api.tabs.onUpdated.removeListener(listener);
        }
      },
    );
  } catch (error) {
    logger.error('failedVideoOpen: error', error);
  }
};
