import { createOrUpdateFeaturesDataAlarm } from '@background/alarmHandlers/createOrUpdateFeaturesDataAlarm';
import { createUpdateSubscriptionInfoAlarm } from '@background/alarmHandlers/createUpdateSubscriptionInfoAlarm';
import { initExtensionMonitoring } from '@background/extensions/extensionMonitor';
import { initNetworkConnectionMonitor } from '@background/network/monitor';
import { initSubscriptionExpiringAlarms } from '@background/subscriptionExpiring/alarms';
import { initSubscriptionExpiringOnYoutubeBackground } from '@background/subscriptionExpiring/subscriptionExpiring';
import { initOneDayDataCleaner } from '@background/utils/initOneDayDataCleaner';
import { initServiceWorkerPingPong } from '@background/utils/initServiceWorkerPingPong';
import { createOrUpdateExchangeRatesAlarm } from '@background/alarmHandlers/createOrUpdateExchangeRatesAlarm';

export async function onOnboardingScreenStatusChanged() {
  initNetworkConnectionMonitor();
  initSubscriptionExpiringOnYoutubeBackground();

  await createOrUpdateFeaturesDataAlarm();
  await createUpdateSubscriptionInfoAlarm();
  await initOneDayDataCleaner();
  await initServiceWorkerPingPong();
  await initSubscriptionExpiringAlarms();
  await initExtensionMonitoring();
  await createOrUpdateExchangeRatesAlarm();
}
