import { Actions } from '@app/actions/shared';
import { GiftMessageHandlerOptions } from '@background/gifts/types';
import { browser_api } from '@app/browser_api';
import { Alarms } from '@app/alarms/shared';
import { getMetaApiData } from '@utils/metaApiData';
import { getLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { acceptGift } from '@api/gifts';
import { getAcceptGiftApiUrl } from '@api/urls';
import { logger } from '@utils/logger';
import { getSubscriptionInfo } from '@utils/getSubscriptionInfo';
import { navigateToExtensionPage } from '@background/utils/navigateToExtensionPage';
import { sendMessageToYoutubeTabs } from '@background/utils/sendMessageToYoutubeTabs';
import { RoutePath } from '@popup/project/youboost/routes/types/RoutePath';
import { getPopupPath } from '../utils';

export const handleGiftMessage = async ({
  message,
  popupAction,
}: GiftMessageHandlerOptions): Promise<void> => {
  try {
    const { imageUrl } = (message as any)?.payload ?? {};
    if (!imageUrl) {
      throw new Error('Missing imageUrl in gift message payload.');
    }

    await browser_api.alarms.clear(Alarms.ShowGiftOnYoutube);

    const { giftsPeriodInMinutes, apiBaseUrl } = await getMetaApiData();

    const periodInMinutes = giftsPeriodInMinutes
      ? Number(giftsPeriodInMinutes)
      : null;

    if (periodInMinutes) {
      browser_api.alarms.create(Alarms.ShowGiftOnYoutube, {
        delayInMinutes: periodInMinutes,
        periodInMinutes,
      });
    }

    const isAcceptingGift = popupAction === Actions.ShowGiftsScreen;
    let shouldOpenRootPage = false;

    if (isAcceptingGift) {
      const { userId, deviceId } = await getLocalStorageData([
        LocalStorageKey.UserId,
        LocalStorageKey.DeviceId,
      ]);

      if (!userId) {
        throw new Error('User ID is not defined.');
      }

      if (!deviceId) {
        throw new Error('Device ID is not defined.');
      }

      try {
        await acceptGift(getAcceptGiftApiUrl(apiBaseUrl), {
          userId,
          deviceId,
        });
      } catch (error) {
        logger.error('handleGiftMessage: error accepting gift', error);
        shouldOpenRootPage = true;
      }
    }

    try {
      if (!shouldOpenRootPage) {
        await getSubscriptionInfo();
        const pathname = getPopupPath(popupAction);
        await navigateToExtensionPage({ pathname, state: { imageUrl } });
      } else {
        await navigateToExtensionPage(RoutePath.Root);
      }
    } catch (error) {
      logger.error('handleGiftMessage: error', error);
    }

    await sendMessageToYoutubeTabs(Actions.HideGift, undefined);
  } catch (error) {
    logger.error('handleGiftMessage: error', error);
  }
};
