import { getExchangeRate } from '@api/getExchangeRate';
import { setLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { logger } from '@utils/logger';

export const updateExchangeRatesAlarm = async () => {
  try {
    const rates = await getExchangeRate();
    await setLocalStorageData({ [LocalStorageKey.ExchangeRatesCache]: rates });
  } catch (e) {
    logger.error('fetchExchangeRateAlarm: error', e);
  }
};
