import { Actions } from '@app/actions/shared';
import { initSubscriptionExpiringAlarms } from '../alarms';
import { logger } from '@utils/logger';
import { MessageHandler } from '@app/infrastructure/types';
import { navigateToExtensionPage } from '@background/utils/navigateToExtensionPage';
import { getPopupPath } from '../utils';

export const subscriptionExpiringToastClickedHandler: MessageHandler<
  Actions.SubscriptionExpiringToastClicked
> = async (message) => {
  const status = message.payload.status;
  try {
    const path = getPopupPath(status);
    if (path) {
      await navigateToExtensionPage(path);
    }
  } catch (error) {
    logger.error('Error handling subscription expiring toast clicked:', error);
  } finally {
    await initSubscriptionExpiringAlarms();
  }
};
