import { Alarms, getChromeAlarm } from '@app/alarms/shared';
import { browser_api } from '@app/browser_api';
import { handleExtensionMonitoring } from './handleExtensionMonitoring';
import { ALARM_MINIMUM_DELAY_IN_MINUTES } from '@app/alarms/constants';

export async function initExtensionMonitoring() {
  browser_api.management.onInstalled.addListener(handleExtensionMonitoring);
  browser_api.management.onUninstalled.addListener(handleExtensionMonitoring);
  browser_api.management.onEnabled.addListener(handleExtensionMonitoring);
  browser_api.management.onDisabled.addListener(handleExtensionMonitoring);

  const periodInMinutes = process.env.MONITORING_EXTENSION_PERIOD_IN_MINUTES
    ? parseInt(process.env.MONITORING_EXTENSION_PERIOD_IN_MINUTES, 10)
    : 30;

  const existingExtensionMonitoringAlarm = await getChromeAlarm(
    Alarms.ExtensionMonitoring,
  );

  if (existingExtensionMonitoringAlarm) {
    await browser_api.alarms.clear(Alarms.ExtensionMonitoring);
  }

  browser_api.alarms.create(Alarms.ExtensionMonitoring, {
    delayInMinutes: ALARM_MINIMUM_DELAY_IN_MINUTES,
    periodInMinutes,
  });

  void handleExtensionMonitoring();
}
