import dayjs from 'dayjs';
import { getMetaApiData } from '@utils/metaApiData';
import { logger } from '@utils/logger';
import { setLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { browser_api } from '@app/browser_api';
import { Actions } from '@app/actions/shared';
import { Alarms } from '@app/alarms/shared';
import { sendMessageToYoutubeTabs } from '@background/utils/sendMessageToYoutubeTabs';

export const handleRefuseGift = async () => {
  try {
    const { giftsAvailableDates } = await getMetaApiData();
    const endDateString = giftsAvailableDates?.[1];
    if (!endDateString) {
      throw new Error('giftsAvailableDates is not defined');
    }

    const endDate = dayjs(endDateString);
    const now = dayjs();
    if (now.isAfter(endDate)) {
      logger.warn('[GIFT] Campaign already ended, nothing to do');
      return;
    }

    logger.info('[GIFT] endDate', endDate);
    await setLocalStorageData({
      [LocalStorageKey.GiftRefusedUntil]: endDate.toISOString(),
    });
    await browser_api.alarms.clear(Alarms.ShowGiftOnYoutube);
    await sendMessageToYoutubeTabs(Actions.HideGift, undefined);
    logger.warn(`[GIFT] Gift feature muted until ${endDate.toISOString()}`);
  } catch (e) {
    logger.error('[GIFT] Error handling refuse gift', e);
  }
};
