import type { PremiumProxies, ProxyConfig } from '../../types/ProxyData';
import { youboostProcessPACData } from '@background/project/youboost/network/proxy/proxyControl/utils';
import { peremenProcessPACData } from '@background/project/peremen/network/proxy/proxyControl/utils';
import { PACDataGeneral } from '@app/storage/local/types/persistentTypes';

export async function processPACData(
  pacData: PACDataGeneral,
  proxies: PremiumProxies,
): Promise<ProxyConfig> {
  // TODO EXT-41 убрать костыль проверки расширения из shared ( process.env.EXTENSION_CODE )
  if (process.env.EXTENSION_CODE === 'peremen') {
    return await peremenProcessPACData(pacData, proxies);
  } else {
    return await youboostProcessPACData(pacData, proxies);
  }
}
