import { featureStore } from '@app/features/list';
import { httpClient } from './httpClient';
import { ProxyFailReason } from '@background/network/proxy/types/ProxyData';
import { getMetaApiData } from '@utils/metaApiData';
import { Feature } from '@app/features/types/Feature';
import { logger } from '@utils/logger';
import { Options } from 'ky';

type ProxyAvailabilitySuccess = {
  isProxyAvailable: true;
};

type ProxyAvailabilityFailure = {
  isProxyAvailable: false;
  onFailReason: ProxyFailReason;
};

type ProxyAvailabilityData =
  | ProxyAvailabilitySuccess
  | ProxyAvailabilityFailure;

const CLIENT_OPTIONS: Options = {
  cache: 'no-store',
  timeout: 10000,
  headers: {
    'Cache-Control': 'no-cache, no-store, must-revalidate',
    Pragma: 'no-cache',
    Expires: '0',
  },
};

export async function checkProxyAvailability(): Promise<ProxyAvailabilityData> {
  try {
    const { featuresList } = await featureStore.getSnapshotAsync();
    const isOnFailDisabled = featuresList[Feature.OnFailDisabledV2];

    if (isOnFailDisabled) {
      return {
        isProxyAvailable: true,
      };
    }

    const metaApiData = await getMetaApiData();
    const proxyUrl = metaApiData?.checkProxyAvailabilityProxyUrl;
    const globalWebUrl = metaApiData?.checkProxyAvailabilityPublicUrl;

    if (!proxyUrl || !globalWebUrl) {
      logger.error('Proxy availability check failed: missing urls:', {
        proxyUrl,
        globalWebUrl,
      });
      return {
        isProxyAvailable: false,
        onFailReason: ProxyFailReason.ProxyNotAvailable,
      };
    }

    const results = await Promise.allSettled([
      httpClient.get(proxyUrl, CLIENT_OPTIONS),
      httpClient.get(globalWebUrl, CLIENT_OPTIONS),
    ]);
    const isProxyAvailableResponse = results[0];
    const isGlobalWebAvailableResponse = results[1];

    const isProxyAvailable =
      isProxyAvailableResponse.status === 'fulfilled' &&
      isProxyAvailableResponse.value?.ok;
    const isGlobalWebAvailable =
      isGlobalWebAvailableResponse.status === 'fulfilled' &&
      isGlobalWebAvailableResponse.value?.ok;

    if (!isProxyAvailable && isGlobalWebAvailable) {
      return {
        isProxyAvailable: false,
        onFailReason: ProxyFailReason.ProxyNotAvailable,
      };
    }

    return {
      isProxyAvailable: true,
    };
  } catch (error) {
    logger.error('checkProxyAvailability error', error);
    return {
      isProxyAvailable: false,
      onFailReason: ProxyFailReason.ProxyNotAvailable,
    };
  }
}
