import {
  getLocalStorageData,
  setLocalStorageData,
} from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { enableProxy } from '../proxyControl';

// This fix was made for preventing multiple proxy starts in a row. We need to rewrite this solution.
let TEMP_SOLUTION_PROXY_STARTED = false;

export async function updateProxyPremiumData(
  shouldStartProxy: boolean = true,
): Promise<void> {
  const { status, hasPremium } = await getLocalStorageData([
    LocalStorageKey.Status,
    LocalStorageKey.HasPremium,
  ]);

  if (hasPremium && status === 'Expired') {
    await setLocalStorageData({
      [LocalStorageKey.TargetState]: 'disconnected',
    });
    return;
  }

  if (shouldStartProxy && !TEMP_SOLUTION_PROXY_STARTED) {
    TEMP_SOLUTION_PROXY_STARTED = true;

    // We need to start it immediately, alarms.create with 0 delay is not working fo Firefox.
    void enableProxy().finally(() => {
      TEMP_SOLUTION_PROXY_STARTED = false;
    });
  }
}
