import { browser_api } from '@app/browser_api';
import { Alarms } from '@app/alarms/shared';
import { getLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { Actions } from '@app/actions/shared';
import { logger } from '@utils/logger';
import { sendMessageToYoutubeTabs } from '@background/utils/sendMessageToYoutubeTabs';

export const giftAlarmHandlerListener = async (
  alarm: browser_api.Alarms.Alarm,
): Promise<void> => {
  const name = alarm.name as Alarms;

  const { currentState } = await getLocalStorageData(
    LocalStorageKey.CurrentState,
  );

  if (name === Alarms.ShowGiftOnYoutube && currentState === 'connected') {
    try {
      await sendMessageToYoutubeTabs(Actions.InitGiftsScript, undefined);
    } catch (error) {
      logger.error('giftAlarmHandlerListener: error', error);
    }
  }
};
