import { subscriptionExpiringToastClickedHandler } from './messageListenersHandler';
import { messageDispatcher } from '@app/infrastructure/messageDispatcher';
import { Actions } from '@app/actions/shared';

export function setupSubscriptionExpiringToastMessageHandler(): void {
  messageDispatcher.register(
    Actions.SubscriptionExpiringToastClicked,
    subscriptionExpiringToastClickedHandler,
  );
}

export function removeSubscriptionExpiringToastMessageHandler(): void {
  messageDispatcher.unregister(
    Actions.SubscriptionExpiringToastClicked,
    subscriptionExpiringToastClickedHandler,
  );
}
