import { getChromePremiumAlarm, PremiumAlarms } from '@app/alarms/premium';
import { createOrUpdatePremiumProxyDataAlarm } from './createOrUpdatePremiumProxyDataAlarm';
import { getMetaApiData } from '@utils/metaApiData';
import { browser_api } from '@app/browser_api';
import { logger } from '@utils/logger';
import { updateSubscriptionInfoAlarm } from './updateSubscriptionInfoAlarm';

export async function createUpdateSubscriptionInfoAlarm() {
  try {
    await createOrUpdatePremiumProxyDataAlarm();

    const existingUpdateSubscriptionInfoAlarm = await getChromePremiumAlarm(
      PremiumAlarms.UpdateSubscriptionInfo,
    );

    const { updateSubscriptionInfoPeriod } = await getMetaApiData();

    if (
      existingUpdateSubscriptionInfoAlarm &&
      existingUpdateSubscriptionInfoAlarm.periodInMinutes !==
        updateSubscriptionInfoPeriod
    ) {
      await browser_api.alarms.clear(PremiumAlarms.UpdateSubscriptionInfo);
    }

    if (
      !existingUpdateSubscriptionInfoAlarm ||
      existingUpdateSubscriptionInfoAlarm.periodInMinutes !==
        updateSubscriptionInfoPeriod
    ) {
      browser_api.alarms.create(PremiumAlarms.UpdateSubscriptionInfo, {
        periodInMinutes: updateSubscriptionInfoPeriod,
        delayInMinutes: updateSubscriptionInfoPeriod,
      });

      void updateSubscriptionInfoAlarm();
    }
  } catch (error) {
    logger.error('createUpdateSubscriptionInfoAlarm: error', error);
  }
}
