import { getProxyCredentials } from './getProxyCredentials';
import { PremiumProxies, ProxyDataResponse } from '../types/ProxyData';
import { setLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';

export async function setupProxyAuth(proxyData: PremiumProxies): Promise<void> {
  if (!!proxyData?.length) {
    const proxyCredential = await getProxyCredentials(proxyData);
    await setLocalStorageData({
      [LocalStorageKey.ProxyCredential]: proxyCredential,
    });
  }
}
