import { setLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { messageDispatcher } from '@app/infrastructure/messageDispatcher';
import { Actions } from '@app/actions/shared';
import { openExtensionPopup } from '@background/utils/openExtensionPopup';
import { logger } from '@utils/logger';
import { NavigateToPathMessage } from '@app/messages/shared';

type PayloadType = Extract<
  NavigateToPathMessage,
  { action: Actions.NavigateToPath }
>['payload'];

export const setDataAndOpenPopup = async (payload: PayloadType) => {
  logger.info('setDataAndOpenPopup path:', payload);
  await setLocalStorageData({ [LocalStorageKey.PopupInitialEntry]: payload });
  await openExtensionPopup();
};

export const navigateToExtensionPage = async (payload: PayloadType) => {
  try {
    logger.info('navigateToExtensionPage path:', payload);
    const response = await messageDispatcher.send({
      action: Actions.NavigateToPath,
      payload,
    });
    if (!response.hasActiveListener) {
      await setDataAndOpenPopup(payload);
    }
  } catch (error) {
    logger.error('navigateToExtensionPage error:', error);
    if (
      error instanceof Error &&
      error.message.includes('Receiving end does not exist')
    ) {
      await setDataAndOpenPopup(payload);
    }
  }
};
