import { PremiumActions } from '@app/actions/premium';
import { PremiumAlarms } from '@app/alarms/premium';
import { browser_api } from '@app/browser_api';
import { getLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { logger } from '@utils/logger';
import {
  PremiumActionResponseMap,
  PremiumMessage,
} from '@app/messages/premium';
import { ALARM_MINIMUM_DELAY_IN_MINUTES } from '@app/alarms/constants';

export const initAdPremiumBannerHandler = async (
  _message: Extract<
    PremiumMessage,
    { action: PremiumActions.InitPremiumBanner }
  >,
): Promise<PremiumActionResponseMap[PremiumActions.InitPremiumBanner]> => {
  logger.info('youboost:Init ad premium banner');
  const { hasPremium } = await getLocalStorageData([
    LocalStorageKey.HasPremium,
  ]);

  const isAlarmEnabled = await browser_api.alarms.get(
    PremiumAlarms.ShowPremiumBannerMedia,
  );

  if (isAlarmEnabled && hasPremium) {
    await browser_api.alarms.clear(PremiumAlarms.ShowPremiumBannerMedia);
    return;
  }

  if (!hasPremium && !isAlarmEnabled) {
    browser_api.alarms.create(PremiumAlarms.ShowPremiumBannerMedia, {
      delayInMinutes: ALARM_MINIMUM_DELAY_IN_MINUTES,
      periodInMinutes: 24 * 60,
    });
  }
};
