import { Actions } from '@app/actions/shared';
import { GiftPopupAction } from '../types';
import { RoutePath } from '@popup/project/youboost/routes/types/RoutePath';

export const GIFTS_POPUP_PATH_MAP: Record<GiftPopupAction, string> = {
  [Actions.ShowGiftsScreen]: RoutePath.GiftAdvertising,
  [Actions.ShowRefuseGiftScreen]: RoutePath.RefuseGift,
};

export const getPopupPath = (action: GiftPopupAction): string => {
  return GIFTS_POPUP_PATH_MAP[action];
};
