import { Actions } from '@app/actions/shared';
import { logger } from '@utils/logger';
import { browser_api } from '@app/browser_api';
import { handleExtensionMonitoring } from '@background/extensions/extensionMonitor/handleExtensionMonitoring';
import { sendMessageToYoutubeTabs } from '@background/utils/sendMessageToYoutubeTabs';
import { MessageHandler } from '@app/infrastructure/types';

export const disableConflictingExtension: MessageHandler<
  Actions.DisableConflictingExtension
> = async (message, { tab }) => {
  try {
    const { extensionId } = message.payload;
    logger.info('runtimeOnMessageListener:Disable conflicting extension');
    await browser_api.management.setEnabled(extensionId, false);
    await handleExtensionMonitoring();
    await sendMessageToYoutubeTabs(
      Actions.ExtensionMonitoringUpdated,
      undefined,
    );
    if (tab?.id) {
      await browser_api.tabs.reload(tab.id);
    }
  } catch (error) {
    logger.error(
      'runtimeOnMessageListener:Failed to disable conflicting extension',
      error,
    );
  }
};
