import {
  CHROME_ERRORS,
  ERROR_URL_PATTERNS,
  FIREFOX_ERRORS,
  ALLOWED_TYPES,
} from './constants';
import { WebRequest } from 'webextension-polyfill';

function urlMatches(url: string): boolean {
  return ERROR_URL_PATTERNS.some((p) => url.includes(p));
}

export function isTargetWebRequestError(
  details: WebRequest.OnErrorOccurredDetailsType,
): boolean {
  const { error: e, url, type } = details;

  if (!ALLOWED_TYPES.includes(type)) return false;
  if (!urlMatches(url)) return false;

  const isChrome = CHROME_ERRORS.some((code) => e === code || e.includes(code));
  const isFirefox = FIREFOX_ERRORS.some(
    (code) => e === code || e.includes(code),
  );

  return isChrome || isFirefox;
}
