import { Actions } from '@app/actions/shared';
import { logger } from '@utils/logger';
import {
  getLocalStorageData,
  setLocalStorageData,
} from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { TWELVE_HOURS_MS } from '@utils/proxy/constants';
import { enableProxy } from '@background/network/proxy/proxyControl';
import { ProxyFailReason } from '@background/network/proxy/types/ProxyData';
import { MessageHandler } from '@app/infrastructure/types';

export const changeServerManually: MessageHandler<
  Actions.ChangeServerManually
> = async () => {
  logger.info('youboost:Change server manually request');
  try {
    const { isAllInternetProxy } = await getLocalStorageData(
      LocalStorageKey.IsAllInternetProxy,
    );

    const now = Date.now();

    const lastKey = isAllInternetProxy
      ? LocalStorageKey.LastManualServerChangeAtAllInternet
      : LocalStorageKey.LastManualServerChangeAtYoutube;

    const { [lastKey]: lastChangedAt } = await getLocalStorageData(lastKey);

    if (typeof lastChangedAt === 'number') {
      const elapsed = now - lastChangedAt;
      if (elapsed < TWELVE_HOURS_MS) {
        return { status: 'rate_limited', waitMs: TWELVE_HOURS_MS - elapsed };
      }
    }

    await enableProxy({
      onFail: true,
      onFailReason: ProxyFailReason.UserManual,
    });

    // await setLocalStorageData({ [lastKey]: now });
    await setLocalStorageData({
      [LocalStorageKey.LastManualServerChangeAtAllInternet]: now,
      [LocalStorageKey.LastManualServerChangeAtYoutube]: now,
    });

    return { status: 'success' };
  } catch (e) {
    return {
      status: 'error',
      message: e instanceof Error ? e.message : 'Unknown error',
    };
  }
};
