import { logger } from '@utils/logger';
import { shouldStartProxy } from '@background/network/proxy/shouldStartProxy/shouldStartProxy';
import { updateProxyPremiumData } from '@background/network/proxy/updateProxyPremiumData/updateProxyPremiumData';
import { updatePacScript } from '@background/pac-script/updatePacScript';
import { setLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { unsetProxy } from '@background/network/proxy/proxyInBrowser';

export async function updateProxyPremiumDataAlarm(): Promise<void> {
  try {
    logger.info('shared:updateProxyPremiumDataAlarm');
    const shouldStart = await shouldStartProxy();

    await updateProxyPremiumData(shouldStart);

    if (shouldStart) {
      await updatePacScript();
    } else {
      await setLocalStorageData({
        [LocalStorageKey.CurrentState]: 'disconnected',
      });
      await unsetProxy();
    }
  } catch (error) {
    logger.error('updateProxyPremiumDataAlarm: error', error);
  }
}
