import { UserStatus } from '@api/premium/types/UserStatus';
import { Actions } from '@app/actions/shared';
import { createAndInitializeUserWithStatus } from '@background/client/premium';
import { logger } from '@utils/logger';
import { MessageHandler } from '@app/infrastructure/types';

export const createNewUserHandler: MessageHandler<
  Actions.CreateNewUser
> = async (message) => {
  logger.info('youboost:Create new user');
  await createAndInitializeUserWithStatus(UserStatus.New, message.payload);
};
