import { Extension } from './types';
import { logger } from '@utils/logger';

export function parseExtensions(
  extensionsString: string | undefined,
): Extension[] {
  try {
    if (!extensionsString) {
      return [];
    }

    return JSON.parse(extensionsString);
  } catch (error) {
    logger.error('parseExtensions: error', error);
    return [];
  }
}
