import {
  getLocalStorageData,
  setLocalStorageData,
} from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';

export async function updateFreeUsageSeconds() {
  try {
    const { freeUsageSecondsLeft, currentState } = await getLocalStorageData([
      LocalStorageKey.FreeUsageSecondsLeft,
      LocalStorageKey.CurrentState,
    ]);

    if (
      !freeUsageSecondsLeft ||
      freeUsageSecondsLeft <= 0 ||
      currentState !== 'connected'
    ) {
      return;
    }

    // Иногда параллельно с этим хэндлером
    // срабатывал хэндлер на сброс секунд resetFreeUsageAlarm.
    // И получалась такая ситуация что в этой функции получено какое-то значение,
    // потом секунды сбрасывались к изначальному значению, но т.к. тут было
    // получено не обновленное значение, то в строчке ниже сброшенные секунды
    // снова перезаписывались на значение до сброса минус 1.
    // Чтобы этого избежать было добавлено условие в хэндлер onFreeUsageSecondsLeftChanged
    await setLocalStorageData({
      [LocalStorageKey.FreeUsageSecondsLeft]: freeUsageSecondsLeft - 1,
    });
  } catch (error) {
    console.error('updateFreeUsageSeconds error', error);
  }
}
