import { PremiumAlarms } from '@app/alarms/premium';
import { Alarms } from '@app/alarms/shared';
import { browser_api } from '@app/browser_api';
import { cleanOneDayDataAlarm } from '@background/alarmHandlers/cleanOneDayDataAlarm';
import { updateSubscriptionInfoAlarm } from '@background/alarmHandlers/updateSubscriptionInfoAlarm';
import { updateProxyPremiumDataAlarm } from '@background/alarmHandlers/updateProxyPremiumDataAlarm';
import { updatePacDataAlarm } from '@background/alarmHandlers/updatePacDataAlarm';
import { logger } from '@utils/logger';
import { enableProxy } from '@background/network/proxy/proxyControl';
import {
  updatePacScriptToFullPAC,
  updatePacScriptToLitePAC,
} from '@background/network/proxy/pacScriptHandlers';
import { enableConnectionButtonAlarm } from '@background/alarmHandlers/enableConnectionButtonAlarm';
import { disableProxyAlarm } from '@background/alarmHandlers/disableProxyAlarm';
import { proxyHealthCheckAlarm } from '@background/alarmHandlers/proxyHealthCheckAlarm';
import { resetFreeUsageAlarm } from '@background/alarmHandlers/resetFreeUsageAlarm';
import { updateFreeUsageSeconds } from '@background/alarmHandlers/updateFreeUsageSeconds';
import { featureStore } from '@app/features/list';
import { handleExtensionMonitoring } from '@background/extensions/extensionMonitor/handleExtensionMonitoring';
import { deleteLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { updateExchangeRatesAlarm } from '@background/alarmHandlers/updateExchangeRatesAlarm';

export async function onAlarmListener(alarm: browser_api.Alarms.Alarm) {
  if (alarm.name === Alarms.CleanOneDayData) {
    logger.info('shared:onAlarmListener:CleanOneDayData');
    await cleanOneDayDataAlarm();
  }

  if (alarm.name === PremiumAlarms.UpdateProxyPremiumData) {
    logger.info('shared:onAlarmListener:UpdateProxyPremiumData');
    await updateProxyPremiumDataAlarm();
  }

  if (alarm.name === PremiumAlarms.UpdateSubscriptionInfo) {
    logger.info('shared:onAlarmListener:UpdateSubscriptionInfo');
    updateSubscriptionInfoAlarm();
  }

  if (alarm.name === Alarms.EnableProxy) {
    logger.info('shared:onAlarmListener:enableProxy');
    await enableProxy();
  }
  if (alarm.name === Alarms.ProxyHealthCheck) {
    logger.info('shared:onAlarmListener:ProxyHealthCheck');
    await proxyHealthCheckAlarm();
  }

  if (alarm.name === Alarms.DisableProxy) {
    logger.info('shared:onAlarmListener:disableProxy');
    await disableProxyAlarm();
  }

  if (alarm.name === Alarms.RestoreLitePAC) {
    logger.info('shared:onAlarmListener:RestoreLitePAC');
    await updatePacScriptToLitePAC();
  }

  if (alarm.name === Alarms.UpdatePacScriptToFullPAC) {
    logger.info('shared:onAlarmListener:UpdatePacScriptToFullPAC');
    await updatePacScriptToFullPAC();
  }

  if (alarm.name === Alarms.EnableConnectionButton) {
    logger.info('shared:onAlarmListener:EnableConnectionButton');
    await enableConnectionButtonAlarm();
  }

  if (alarm.name === Alarms.UpdatePacData) {
    logger.info('shared:onAlarmListener:UpdatePacData');
    await updatePacDataAlarm();
  }

  if (alarm.name === Alarms.FreeUsageReset) {
    logger.info('shared:onAlarmListener:FreeUsageReset');
    await resetFreeUsageAlarm();
  }

  if (alarm.name === Alarms.FreeUsage) {
    await updateFreeUsageSeconds();
  }

  if (alarm.name === Alarms.UpdateFeaturesData) {
    logger.info('shared:onAlarmListener:UpdateFeaturesData');
    await featureStore.init();
  }

  if (alarm.name === Alarms.ExtensionMonitoring) {
    await handleExtensionMonitoring();
  }

  if (
    alarm.name === Alarms.ExtensionConflictWarningProxy ||
    alarm.name === Alarms.ExtensionConflictWarningAdBlocker
  ) {
    await browser_api.alarms.clear(alarm.name);

    if (alarm.name === Alarms.ExtensionConflictWarningAdBlocker) {
      await deleteLocalStorageData(
        LocalStorageKey.IsExtensionConflictWarningAdBlockerAlarmExisted,
      );
    }
  }

  if (alarm.name === Alarms.UpdateExchangeRatesAlarm) {
    await updateExchangeRatesAlarm();
  }
}
