import { fetchPACData, fetchPACRegistry } from '@api/fetchPACData';
import {
  getLocalStorageData,
  setLocalStorageData,
} from '@app/storage/local/shared';
import {
  PACData,
  PACPremiumData,
  PACRegistryData,
} from '@app/storage/local/types/persistentTypes';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { getIsLitePACFeatureEnabled } from '@background/utils/getIsLitePACFeatureEnabled';
import { getIsLitePACEnabled } from '@background/utils/getIsLitePACEnabled';
import { isPACData } from '@background/pac-script/utils/isPACData';
import { isPACPremiumData } from '@background/pac-script/utils/isPACPremiumData';

export async function getYouboostPACData({
  shouldRefetch = false,
  isLitePACInner,
}: {
  shouldRefetch?: boolean;
  isLitePACInner?: boolean;
}): Promise<PACData | PACPremiumData> {
  let shouldUpdate = shouldRefetch;

  const registry = await fetchPACRegistry<PACRegistryData>();

  const { hasPremium } = await getLocalStorageData(LocalStorageKey.HasPremium);

  const isLitePACFeatureEnabled = await getIsLitePACFeatureEnabled();
  const isLitePACEnabled = await getIsLitePACEnabled();

  const shouldFetchLitePACData =
    !isLitePACEnabled && (isLitePACInner ?? isLitePACFeatureEnabled);

  if (hasPremium) {
    const { pacPremiumData } = await getLocalStorageData(
      LocalStorageKey.PACPremiumData,
    );

    if (!shouldUpdate && pacPremiumData !== undefined) {
      return pacPremiumData;
    }

    const registryUrl =
      shouldFetchLitePACData && registry.premiumLite
        ? registry.premiumLite
        : registry.premium;

    const data = await fetchPACData<PACPremiumData>(registryUrl);

    await setLocalStorageData({ [LocalStorageKey.PACPremiumData]: data });
    return data;
  }

  const { pacData } = await getLocalStorageData(LocalStorageKey.PACData);

  if (
    !shouldUpdate &&
    pacData &&
    (isPACData(pacData) || isPACPremiumData(pacData))
  ) {
    return pacData;
  }

  const registryUrl =
    shouldFetchLitePACData && registry.freeLite
      ? registry.freeLite
      : registry.free;

  const data = await fetchPACData<PACData>(registryUrl);

  await setLocalStorageData({ [LocalStorageKey.PACData]: data });

  return data;
}
