import { PACDataGeneral } from '@app/storage/local/types/persistentTypes';
import { getYouboostPACData } from '@background/project/youboost/pac-script/utils';
import { getPeremenPACData } from '@background/project/peremen/pac-script/utils';

export async function getPACData({
  shouldRefetch = false,
  isLitePACInner,
}: {
  shouldRefetch?: boolean;
  isLitePACInner?: boolean;
}): Promise<PACDataGeneral> {
  // TODO EXT-41 убрать костыль проверки расширения из shared ( process.env.EXTENSION_CODE )
  if (process.env.EXTENSION_CODE === 'peremen') {
    return await getPeremenPACData({ shouldRefetch });
  } else {
    return await getYouboostPACData({ shouldRefetch, isLitePACInner });
  }
}
