import { HTTPError } from 'ky';
import { httpClient } from '@api/httpClient';
import { getProxyWithSubscriptionApiUrl } from '@api/urls';
import { ProxyFailReason } from '@background/network/proxy/types/ProxyData';
import { featureStore } from '@app/features/list';
import { Feature } from '@app/features/types/Feature';
import { logger } from '@utils/logger';
import {
  ProxyWithSubscriptionError,
  ProxyWithSubscriptionResponse,
} from './types';

export async function fetchProxyWithSubscription({
  apiBaseUrl,
  deviceId,
  deviceIp,
  userId,
  onFail,
  onFailReason,
}: {
  apiBaseUrl: string;
  deviceId: string;
  deviceIp?: string;
  userId?: string;
  onFail?: boolean;
  onFailReason?: ProxyFailReason;
}): Promise<ProxyWithSubscriptionResponse | ProxyWithSubscriptionError> {
  try {
    const apiUrl = getProxyWithSubscriptionApiUrl(apiBaseUrl);
    const { featuresList } = await featureStore.getSnapshotAsync();

    const data = await httpClient
      .post<ProxyWithSubscriptionResponse>(apiUrl, {
        json: {
          userId,
          deviceId,
          deviceIp,
          onFail,
          onFailReason,
          withAuth: featuresList[Feature.ProxyAuth],
        },
      })
      .json();

    return data;
  } catch (error) {
    logger.error('fetchProxyWithSubscription: error', error);
    if (error instanceof HTTPError) {
      const errorData = await error.response.json<{
        error: ProxyWithSubscriptionError['error'];
      }>();
      if (error.response.status === 400) {
        if (errorData.error.code === 'change_device') {
          return { data: null, error: errorData.error };
        }

        if (errorData.error.code === 'user_not_found') {
          return { data: null, error: errorData.error };
        }
      }
      if (error.response.status === 500) {
        if (errorData.error.code === 'proxy_not_found') {
          return { data: null, error: errorData.error };
        }
        return {
          data: null,
          error: { code: 'internal', localized_message: 'Internal error' },
        };
      }
    }
    if (error instanceof Error && error.message === 'Failed to fetch') {
      return {
        data: null,
        error: {
          code: 'requestBlockedError',
          localized_message: 'Request blocked error',
        },
      };
    }
    return {
      data: null,
      error: {
        code: 'unknown',
        localized_message: 'Unknown error',
      },
    };
  }
}
