import { Feature, type FeatureList } from '@app/features/types/Feature';
import type { SupportedLanguages } from '../types';

const EXTENSION = process.env.EXTENSION_CODE;
export async function getSupportedLanguages(
  featuresList: Partial<FeatureList>,
): Promise<Array<SupportedLanguages>> {
  const isMultiLocaleSupported = featuresList[Feature.MultiLocalesSupport];
  if (!isMultiLocaleSupported) return ['ru'] as const;

  if (EXTENSION === 'youboost') {
    return ['ru', 'en', 'pl', 'es', 'pt', 'de', 'fr', 'tr', 'it'] as const;
  }

  return ['ru', 'en'] as const;
}
