import {
  getLocalStorageData,
  setLocalStorageData,
} from '@app/storage/local/shared';
import { MetaApiData } from '@app/storage/local/types/expirableTypes';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { setUninstallUrl } from '@background/utils/setUninstallUrl';
import { logger } from '@utils/logger';
import { initMidRollAlarm } from '../utils/initMidRollAlarm';
import { browser_api } from '@app/browser_api';
import { PremiumAlarms } from '@app/alarms/premium';

export async function storageLocalOnChangedListener(changes: {
  hasPremium?: { newValue: boolean };
  userId?: { newValue: string };
  deviceId?: { newValue: string };
  configsBaseUrl?: { newValue: string };
  metaApiData?: { newValue: MetaApiData; oldValue: MetaApiData };
}) {
  if (changes.hasPremium) {
    logger.info('youboost:hasPremium changed');
    await setLocalStorageData({
      [LocalStorageKey.IsAdBannerShown]: !changes.hasPremium.newValue,
    });
  }

  if (changes.userId && changes.userId.newValue) {
    logger.info('userId changed');
    const { deviceId } = await getLocalStorageData(LocalStorageKey.DeviceId);

    if (deviceId) {
      await setUninstallUrl(changes.userId.newValue, deviceId);
    }
  }

  if (changes.deviceId && changes.deviceId.newValue) {
    logger.info('deviceId changed');
    const { userId } = await getLocalStorageData(LocalStorageKey.UserId);
    if (userId) {
      await setUninstallUrl(userId, changes.deviceId.newValue);
    }
  }

  // we need to reset url when configsBaseUrl is changed
  if (changes.configsBaseUrl && changes.configsBaseUrl.newValue) {
    logger.info('configsBaseUrl changed');
    const { userId, deviceId } = await getLocalStorageData([
      LocalStorageKey.UserId,
      LocalStorageKey.DeviceId,
    ]);

    if (userId && deviceId) {
      await setUninstallUrl(userId, deviceId);
    }
  }

  if (
    changes?.metaApiData?.newValue?.midpointMediaIntervalInMinutes &&
    changes?.metaApiData?.newValue?.midpointMediaIntervalInMinutes !==
      changes?.metaApiData?.oldValue?.midpointMediaIntervalInMinutes
  ) {
    logger.info('youboost:metaApiData:midpointMediaIntervalInMinutes changed');
    await browser_api.alarms.clear(PremiumAlarms.ShowMidpointMedia);
    await initMidRollAlarm();
  }
}
