import { httpClient } from '@api/httpClient';
import { getExchangeRateApiUrl } from '@api/urls';
import { getMetaApiData } from '@utils/metaApiData';
import type { ExchangeRateResponseType, GetExchangeRateType } from './types';
import { logger } from '@utils/logger';

export const getExchangeRate: GetExchangeRateType = async () => {
  try {
    const { apiBaseUrl } = await getMetaApiData();
    const exchangeRateApiUrl = getExchangeRateApiUrl(apiBaseUrl);
    return await httpClient
      .get<ExchangeRateResponseType>(exchangeRateApiUrl)
      .json();
  } catch (error) {
    logger.error('fetchExchangeRate: error', error);
    throw error;
  }
};
