import { logger } from '@utils/logger';
import { updateExchangeRatesAlarm } from '@background/alarmHandlers/updateExchangeRatesAlarm';
import { Alarms, getChromeAlarm } from '@app/alarms/shared';
import { browser_api } from '@app/browser_api';
import { getMetaApiData } from '@utils/metaApiData';

const ALARM_NAME = Alarms.UpdateExchangeRatesAlarm;

export const createOrUpdateExchangeRatesAlarm = async () => {
  try {
    const { exchangeRatesUpdatePeriodInMinutes } = await getMetaApiData();
    if (!exchangeRatesUpdatePeriodInMinutes) return;

    const alarm = await getChromeAlarm(ALARM_NAME);
    if (alarm) {
      await browser_api.alarms.clear(ALARM_NAME);
    }

    browser_api.alarms.create(ALARM_NAME, {
      periodInMinutes: exchangeRatesUpdatePeriodInMinutes,
      delayInMinutes: exchangeRatesUpdatePeriodInMinutes,
    });
    await updateExchangeRatesAlarm();
  } catch (e) {
    logger.error('createOrUpdateExchangeRatesAlarm: error', e);
  }
};
