import { logger } from '@utils/logger';

// Глобальная переменная для отслеживания текущего blob URL
let currentBlobUrl: string | null = null;

/**
 * Освобождает предыдущий blob URL, если он существует
 * @param newUrl - новый URL для установки (опционально)
 */
export function revokeBlobUrl(newUrl?: string): void {
  if (currentBlobUrl) {
    URL.revokeObjectURL(currentBlobUrl);
    currentBlobUrl = null;
    logger.info('Previous blob URL revoked to prevent memory leak');
  }
  currentBlobUrl = newUrl || null;
}
