import {
  getLocalStorageData,
  setLocalStorageData,
} from '@app/storage/local/shared';
import { ProxyFailReason } from '../../types/ProxyData';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import {
  fetchProxyWithSubscription,
  ProxyWithSubscriptionResponse,
} from '@api/premium/fetchProxyWithSubscription';
import { updateSubscriptionStorage } from '@utils/subscription/updateSubscriptionStorage';
import { browser_api } from '@app/browser_api';
import { Actions } from '@app/actions/shared';

export async function getProxyDataWithStatus({
  apiBaseUrl,
  deviceId,
  deviceIp,
  onFail,
  onFailReason,
}: {
  apiBaseUrl: string;
  deviceId: string;
  deviceIp?: string;
  onFail?: boolean;
  onFailReason?: ProxyFailReason;
}): Promise<ProxyWithSubscriptionResponse> {
  const { userId } = await getLocalStorageData([LocalStorageKey.UserId]);

  const response = await fetchProxyWithSubscription({
    apiBaseUrl,
    userId,
    deviceId,
    deviceIp,
    onFail,
    onFailReason,
  });

  if ('error' in response && response.error !== null) {
    if (response.error.code === 'change_device') {
      await browser_api.runtime.sendMessage({
        action: Actions.OpenPopupChangeDevice,
      });
      await setLocalStorageData({
        [LocalStorageKey.IsChangeDeviceError]: true,
        [LocalStorageKey.TargetState]: 'disconnected',
      });
    }
    if (response.error.code === 'proxy_not_found') {
      await setLocalStorageData({ currentState: 'error' });
    }
    throw new Error(response.error.code);
  }

  // Sync subscription data
  await updateSubscriptionStorage(response);

  // Save last successful proxy request timestamp
  await setLocalStorageData({
    [LocalStorageKey.LastProxyRequestAt]: Date.now(),
  });

  return response;
}
