import type { Alarms } from 'webextension-polyfill';
import { browser_api } from '@app/browser_api';

export enum PremiumAlarms {
  UpdateProxyPremiumData = 'updateProxyPremiumData',
  UpdateSubscriptionInfo = 'updateSubscriptionInfo',
  ShowPremiumBannerMedia = 'showPremiumBannerMedia',
  HidePremiumBannerMedia = 'hidePremiumBannerMedia',
  PaymentStarted = 'paymentStarted',
  PremiumCanceled = 'premiumCanceled',
  ShowMidpointMedia = 'showMidpointMedia',
}

export async function getChromePremiumAlarm(
  name: PremiumAlarms,
): Promise<Alarms.Alarm | undefined> {
  return await browser_api.alarms.get(name);
}
