import { PremiumAlarms } from '@app/alarms/premium';
import { browser_api } from '@app/browser_api';
import { logger } from '@utils/logger';
import { getMetaApiData } from '@utils/metaApiData';
import {
  PremiumActionResponseMap,
  PremiumMessage,
} from '@app/messages/premium';
import { PremiumActions } from '@app/actions/premium';

export const paymentStartedHandler = async (
  _message: Extract<PremiumMessage, { action: PremiumActions.PaymentStarted }>,
): Promise<PremiumActionResponseMap[PremiumActions.PaymentStarted]> => {
  logger.info('youboost:Payment started');
  const { premiumBannerPeriodInMinutes = 24 * 60 } = await getMetaApiData();

  browser_api.alarms.create(PremiumAlarms.PaymentStarted, {
    periodInMinutes: premiumBannerPeriodInMinutes,
  });
};
