import { Actions } from '@app/actions/shared';
import { logger } from '@utils/logger';
import { setLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { MessageHandler } from '@app/infrastructure/types';

export const saveTime: MessageHandler<Actions.SaveTime> = async (message) => {
  try {
    logger.info('runtimeOnMessageListener:Save time');
    const { time, videoId } = message.payload;

    await setLocalStorageData({
      [LocalStorageKey.SavedTime]: {
        [videoId]: Math.round(time),
      },
    });
  } catch (error) {
    logger.error('saveTime: error', error);
  }
};
