import { PremiumAlarms } from '@app/alarms/premium';
import { browser_api } from '@app/browser_api';
import { logger } from '@utils/logger';
import {
  PremiumActionResponseMap,
  PremiumMessage,
} from '@app/messages/premium';
import { PremiumActions } from '@app/actions/premium';
import { ALARM_MINIMUM_DELAY_IN_MINUTES } from '@app/alarms/constants';

export const closeAdPremiumBannerHandler = async (
  _message: Extract<
    PremiumMessage,
    { action: PremiumActions.ClosePremiumBanner }
  >,
): Promise<PremiumActionResponseMap[PremiumActions.ClosePremiumBanner]> => {
  logger.info('youboost:Close ad premium banner');
  browser_api.alarms.create(PremiumAlarms.HidePremiumBannerMedia, {
    delayInMinutes: ALARM_MINIMUM_DELAY_IN_MINUTES,
  });
};
