import { getLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { browser_api } from '@app/browser_api';
import { Alarms } from '@app/alarms/shared';
import { checkProxyAvailability } from '@api/checkProxyAvailability';
import { enableProxy } from '@background/network/proxy/proxyControl';

export const proxyHealthCheck = async () => {
  const { enableProxyOnFailMaxRetryAttempts, currentState } =
    await getLocalStorageData([
      LocalStorageKey.EnableProxyOnFailMaxRetryAttempts,
      LocalStorageKey.CurrentState,
    ]);

  if (currentState !== 'connected') return;
  if (
    !enableProxyOnFailMaxRetryAttempts ||
    enableProxyOnFailMaxRetryAttempts <= 0
  ) {
    await browser_api.alarms.clear(Alarms.ProxyHealthCheck);
    return;
  }

  const result = await checkProxyAvailability();
  if (!result.isProxyAvailable) {
    await enableProxy({
      onFail: true,
      onFailReason: result.onFailReason,
    });
  }
};
