import { Actions } from '@app/actions/shared';
import { logger } from '@utils/logger';
import { sendMessageToYoutubeTabs } from '@background/utils/sendMessageToYoutubeTabs';
import { MessageHandler } from '@app/infrastructure/types';

export const hideAllToasts: MessageHandler<
  Actions.HideAllToasts
> = async () => {
  try {
    logger.info('runtimeOnMessageListener:hideAllToasts');
    await sendMessageToYoutubeTabs(Actions.HideAllToasts, undefined);
  } catch (error) {
    logger.error('hideAllToasts: error', error);
  }
};
