import { logger } from '@utils/logger';
import { MessageHandler } from '@app/infrastructure/types';
import { Actions } from '@app/actions/shared';
import { featureStore } from '@app/features/list';
import { Feature } from '@app/features/types/Feature';
import {
  initSubscriptionExpiringAlarms,
  removeSubscriptionExpiringAlarmHandler,
  setupSubscriptionExpiringAlarmHandler,
} from '@background/subscriptionExpiring/alarms';
import {
  removeSubscriptionExpiringToastMessageHandler,
  setupSubscriptionExpiringToastMessageHandler,
} from '@background/subscriptionExpiring/messageListeners';
import {
  removeStorageListener,
  setupStorageListener,
} from '@background/subscriptionExpiring/storageListener';

export const initSubscriptionExpiringScriptReadyHandler: MessageHandler<
  Actions.InitSubscriptionExpiringScriptReady
> = async () => {
  try {
    logger.info('shared:InitSubscriptionExpiringScriptReady device');
    const { featuresList } = await featureStore.getSnapshotAsync();

    if (featuresList?.[Feature.SubscriptionExpiringAlerts]) {
      setupSubscriptionExpiringAlarmHandler();
      setupSubscriptionExpiringToastMessageHandler();
      initSubscriptionExpiringAlarms();
      setupStorageListener();
    } else {
      removeSubscriptionExpiringAlarmHandler();
      removeSubscriptionExpiringToastMessageHandler();
      removeStorageListener();
    }
  } catch (error) {
    logger.error('deactivateDeviceHandler: error', error);
  }
};
