import {
  getLocalStorageData,
  setLocalStorageData,
} from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { openExtensionPopup } from './openExtensionPopup';
import { logger } from '@utils/logger';

export function initOpenPopupIfError() {
  setTimeout(async () => {
    try {
      const { shouldOpenPopup } = await getLocalStorageData(
        LocalStorageKey.ShouldOpenPopup,
      );

      if (shouldOpenPopup) {
        await openExtensionPopup();
        await setLocalStorageData({ [LocalStorageKey.ShouldOpenPopup]: false });
      }
    } catch (error) {
      logger.error('initOpenPopupIfError: error', error);
    }
  }, 1000);
}
