import { getCreateNewUserApiUrl } from '@api/urls';
import { createNewUser } from '@api/premium/createNewUser';
import { getMetaApiData } from '@utils/metaApiData';
import { getDeviceId } from '@app/storage/utils/getDeviceId';
import { getDeviceIP } from '@app/storage/utils/getDeviceIP';
import { analytics } from '../analytics/ga';
import { UserStatus } from '@api/premium/types/UserStatus';
import { setLocalStorageData } from '@app/storage/local/shared';
import { OnboardingStep } from '@popup/project/youboost-neo/components/Onboarding/ui/constants';
import { Actions } from '@app/actions/shared';
import { setCookieData } from '@app/storage/cookies/shared';
import { setupTariffFree } from '@api/premium/setupTariffFree';
import { setupTariff } from '@api/premium/fetchPremiumData';
import { Tariff } from '@api/premium/types/Tariff';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { getSubscriptionInfo } from '@utils/getSubscriptionInfo';
import { processError } from '../utils/processError';
import { messageDispatcher } from '@app/infrastructure/messageDispatcher';
import { navigateToExtensionPage } from '@background/utils/navigateToExtensionPage';
import { RoutePath } from '@popup/project/peremen/routes/types/RoutePath';

export async function moveUserToFreeTariff(userId: string) {
  try {
    const [deviceId, deviceIp, { apiBaseUrl }] = await Promise.all([
      getDeviceId(),
      getDeviceIP(),
      getMetaApiData(),
    ]);

    const response = await setupTariffFree(apiBaseUrl, {
      userId,
      deviceId,
      deviceIp,
    });

    await setLocalStorageData({
      status: response?.data?.subscription?.status,
    });
    await setLocalStorageData({ hasPremium: false });
  } catch (error) {
    await processError(error);
  }
}

export async function setupFreeTrial(userId: string) {
  try {
    const [deviceId, deviceIp, { apiBaseUrl }] = await Promise.all([
      getDeviceId(),
      getDeviceIP(),
      getMetaApiData(),
    ]);

    await setupTariff(apiBaseUrl, {
      userId,
      deviceId,
      deviceIp,
      tariff: Tariff.FreeTrial,
      isAutoRenew: false,
    });

    await setLocalStorageData({
      [LocalStorageKey.TargetState]: 'connected',
    });
  } catch (error) {
    await processError(error);
  }
}

export async function createAndInitializeUserWithStatus(
  userStatus?: UserStatus,
  payload?: {
    isSaleActive: boolean;
    isGuestMode: boolean;
    isTrial: boolean;
  },
): Promise<string> {
  try {
    const [deviceId, deviceIp, { apiBaseUrl }] = await Promise.all([
      getDeviceId(),
      getDeviceIP(),
      getMetaApiData(),
    ]);

    const { userId } = await createNewUser({
      url: getCreateNewUserApiUrl(apiBaseUrl),
      deviceId,
      deviceIp,
    });

    if (payload?.isGuestMode) {
      await moveUserToFreeTariff(userId);
    }

    if (payload?.isTrial) {
      try {
        await setupTariff(apiBaseUrl, {
          userId,
          deviceId,
          deviceIp,
          tariff: Tariff.FreeTrial,
          isAutoRenew: false,
        });
      } catch (error) {
        // TODO EXT-41 убрать костыль проверки расширения из shared ( process.env.EXTENSION_CODE )
        if (
          process.env.EXTENSION_CODE === 'peremen' ||
          process.env.EXTENSION_CODE === 'youboost'
        ) {
          await navigateToExtensionPage(RoutePath.UnavailableTrial);
        } else {
          messageDispatcher.send({
            action: Actions.NavigateToUnavailableTrial,
          });
        }
      }
    }

    await setLocalStorageData({
      userId,
    });

    const { cookieDomain } = await getMetaApiData();

    await setCookieData(
      {
        userId,
      },
      cookieDomain,
    );

    await analytics.trackUserAction('user_created', 'premium');

    await getSubscriptionInfo();

    await setLocalStorageData({
      [LocalStorageKey.OnboardingScreenStatus]: OnboardingStep.Done,
    });

    // TODO EXT-41 убрать костыль проверки расширения из shared ( process.env.EXTENSION_CODE )
    if (
      process.env.EXTENSION_CODE === 'peremen' ||
      process.env.EXTENSION_CODE === 'youboost'
    ) {
      if (!(payload?.isTrial || payload?.isGuestMode)) {
        await navigateToExtensionPage({
          pathname: RoutePath.Tariffs,
          state: {
            hasOneMonthDiscount: payload?.isSaleActive ?? false,
          },
        });
      }
    } else {
      messageDispatcher.send({
        action: Actions.CreateNewUserSuccess,
        payload: {
          isSaleActive: payload?.isSaleActive || false,
          isGuestMode: payload?.isGuestMode || false,
          isTrial: payload?.isTrial || false,
        },
      });
    }

    return userId;
  } catch (error) {
    if (error instanceof Error && error.message === 'Failed to fetch') {
      await setLocalStorageData({
        requestBlockedError: 'request createNewUser is probably blocked',
      });
      await analytics.trackError(error.message, 'user_creation_failed');
    }

    await processError(error);

    return '';
  }
}
