import {
  BaseProxyDataResponse,
  PremiumProxies,
  PremiumProxyDataResponse,
  ProxyCredential,
  ProxyDataResponse,
} from '../types/ProxyData';
import { getLocalStorageData } from '@app/storage/local/shared';

import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';

export async function getProxyCredentials(proxyData: PremiumProxies) {
  function parseAuthString(authString: string) {
    const userName = authString.split(':')[0] || '';
    const password = authString.split(':').slice(1).join(':') || '';
    return { userName, password };
  }

  const result: ProxyCredential = {};

  for (const proxy of proxyData) {
    const authString = proxy.auth || '';

    const proxyHost = proxy.host;
    const proxyPort = proxy.port;

    const { userName, password } = parseAuthString(authString);

    result[`${proxyHost}:${proxyPort}`] = {
      userName,
      password,
      proxyType: proxy.proxy_type,
    };
  }

  return result;
}
