import { browser_api } from '@app/browser_api';
import { ActionPayloadMap } from '@app/messages/shared';
import { logger } from '@utils/logger';

export const YOUTUBE_URLS = ['*://*.youtube.com/*'];

export async function sendMessageToYoutubeTabs<
  T extends keyof ActionPayloadMap,
>(action: T, payload: ActionPayloadMap[T]): Promise<void> {
  try {
    const tabs = await browser_api.tabs.query({ url: YOUTUBE_URLS });
    await Promise.all(
      tabs.map((tab) => {
        if (tab.id && tab.url) {
          return browser_api.tabs.sendMessage(tab.id!, { action, payload });
        }
        return null;
      }),
    );
  } catch (error) {
    logger.error(
      '[SEND MESSAGE TO YOUTUBE TABS] Error',
      error,
      action,
      payload,
    );
  }
}
