import { browser_api } from '@app/browser_api';
import { getMetaApiData } from '@utils/metaApiData';
import { logger } from '@utils/logger';
import { Alarms, getChromeAlarm } from '@app/alarms/shared';
import { ALARM_MINIMUM_DELAY_IN_MINUTES } from '@app/alarms/constants';

export async function initGiftAlarms(): Promise<void> {
  try {
    const { giftsPeriodInMinutes } = await getMetaApiData();

    const periodInMinutes = giftsPeriodInMinutes
      ? Number(giftsPeriodInMinutes)
      : null;

    const existingAlarm = await getChromeAlarm(Alarms.ShowGiftOnYoutube);

    if (existingAlarm) {
      browser_api.alarms.clear(Alarms.ShowGiftOnYoutube);
    }

    if (periodInMinutes && !existingAlarm) {
      browser_api.alarms.create(Alarms.ShowGiftOnYoutube, {
        delayInMinutes: ALARM_MINIMUM_DELAY_IN_MINUTES,
        periodInMinutes,
      });
    }
  } catch (error) {
    logger.error('initGiftAlarms: error', error);
  }
}
