import { Alarms } from '@app/alarms/shared';
import { browser_api } from '@app/browser_api';
import {
  getLocalStorageData,
  setLocalStorageData,
} from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { unsetProxy } from './unsetProxy';
import { handleProxySetError } from './utils/handleProxySetError';
import { revokeBlobUrl } from './utils/blobUrlManager';
import { ALARM_MINIMUM_DELAY_IN_MINUTES } from '@app/alarms/constants';

export async function clearProxy(): Promise<void> {
  // Освобождаем blob URL перед очисткой прокси настроек
  revokeBlobUrl();

  await unsetProxy();

  const { targetState } = await getLocalStorageData(
    LocalStorageKey.TargetState,
  );
  if (browser_api.runtime.lastError) {
    handleProxySetError(
      'Error clearing proxy settings:',
      browser_api.runtime.lastError.message,
    );
  } else if (targetState === 'connected') {
    browser_api.alarms.create(Alarms.EnableProxy, {
      delayInMinutes: ALARM_MINIMUM_DELAY_IN_MINUTES,
    });
  } else {
    await setLocalStorageData({ currentState: 'disconnected' });
    await browser_api.alarms.clear(Alarms.ProxyHealthCheck);
  }
}
