import { createOrUpdatePremiumProxyDataAlarm } from '@background/alarmHandlers/createOrUpdatePremiumProxyDataAlarm';
import { logger } from '@utils/logger';

export async function onHasPremiumChanged() {
  try {
    logger.info('shared:onHasPremiumChanged');

    await createOrUpdatePremiumProxyDataAlarm();
  } catch (error) {
    logger.error('onHasPremiumChanged: error', error);
  }
}
