import {
  getLocalStorageData,
  setLocalStorageData,
} from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { browser_api } from '@app/browser_api';
import {
  sendMessageToYoutubeTabs,
  YOUTUBE_URLS,
} from '@background/utils/sendMessageToYoutubeTabs';
import { Actions } from '@app/actions/shared';
import { Alarms } from '@app/alarms/shared';
import {
  ENABLE_PROXY_ON_FAIL_MAX_RETRY_ATTEMPTS,
  ENABLE_PROXY_ON_FAIL_PERIOD_IN_MINUTES,
} from '@background/network/proxy/proxyControl/utils/constants';

export const onProxySuccess = async () => {
  const { isNetworkError } = await getLocalStorageData([
    LocalStorageKey.IsNetworkError,
  ]);

  if (isNetworkError) {
    const tabs = await browser_api.tabs.query({ url: YOUTUBE_URLS });
    tabs.forEach((tab) => {
      if (!tab.url || !tab.id) return;
    });

    await sendMessageToYoutubeTabs(
      Actions.NetworkConnectionRetrySuccess,
      undefined,
    );
  }

  // 1. Восстановить счетчик попыток
  await setLocalStorageData({
    [LocalStorageKey.CurrentState]: 'connected',
    [LocalStorageKey.EnableProxyOnFailMaxRetryAttempts]:
      ENABLE_PROXY_ON_FAIL_MAX_RETRY_ATTEMPTS,
    [LocalStorageKey.isNetworkErrorHandlingInProgress]: false,
    [LocalStorageKey.IsNetworkError]: false,
  });

  // 2. Запустить мониторинг
  const alarm = await browser_api.alarms.get(Alarms.ProxyHealthCheck);
  if (alarm) {
    await browser_api.alarms.clear(Alarms.ProxyHealthCheck);
  }
  browser_api.alarms.create(Alarms.ProxyHealthCheck, {
    periodInMinutes: ENABLE_PROXY_ON_FAIL_PERIOD_IN_MINUTES,
  });
};
