import { getLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';

export async function shouldStartProxy(): Promise<boolean> {
  const {
    userId,
    currentState,
    targetState,
    isNetworkErrorHandlingInProgress,
  } = await getLocalStorageData([
    LocalStorageKey.UserId,
    LocalStorageKey.CurrentState,
    LocalStorageKey.TargetState,
    LocalStorageKey.isNetworkErrorHandlingInProgress,
  ]);

  return Boolean(
    userId && currentState === 'connected' && !isNetworkErrorHandlingInProgress,
  );
}
