import {
  getLocalStorageData,
  setLocalStorageData,
} from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import {
  ENABLE_PROXY_ON_FAIL_ERROR_MESSAGE,
  ENABLE_PROXY_ON_FAIL_MAX_RETRY_ATTEMPTS,
} from '@background/network/proxy/proxyControl/utils/constants';
import { Actions } from '@app/actions/shared';
import { sendMessageToYoutubeTabs } from '@background/utils/sendMessageToYoutubeTabs';
import { browser_api } from '@app/browser_api';
import { Alarms } from '@app/alarms/shared';
import { logger } from '@utils/logger';

export const onProxyFailed = async (): Promise<boolean> => {
  const { enableProxyOnFailMaxRetryAttempts } = await getLocalStorageData([
    LocalStorageKey.EnableProxyOnFailMaxRetryAttempts,
  ]);

  // 1. Декремент счетчика
  const newAttempts =
    (enableProxyOnFailMaxRetryAttempts ??
      ENABLE_PROXY_ON_FAIL_MAX_RETRY_ATTEMPTS) - 1;

  // 2. Проверка лимита
  if (newAttempts < 0) {
    console.error('Max retry attempts reached');
    logger.info(
      `enableProxyOnFailAlarm: ENABLE_PROXY_ON_FAIL_ERROR_MESSAGE:${ENABLE_PROXY_ON_FAIL_ERROR_MESSAGE}`,
    );
    logger.info('IsConnectionButtonDisabled', true);
    logger.info('CurrentState', 'error');
    logger.info('isNetworkErrorHandlingRetriesFailed', true);
    await setLocalStorageData({
      [LocalStorageKey.ErrorMessage]: ENABLE_PROXY_ON_FAIL_ERROR_MESSAGE,
      [LocalStorageKey.IsConnectionButtonDisabled]: true,
      [LocalStorageKey.EnableProxyOnFailMaxRetryAttempts]:
        ENABLE_PROXY_ON_FAIL_MAX_RETRY_ATTEMPTS,
      [LocalStorageKey.CurrentState]: 'error',
      [LocalStorageKey.IsNetworkError]: true,
      [LocalStorageKey.isNetworkErrorHandlingInProgress]: false,
    });

    await sendMessageToYoutubeTabs(
      Actions.NetworkConnectionRetryFail,
      undefined,
    );
    await browser_api.alarms.clear(Alarms.ProxyHealthCheck);
    return false;
  }

  logger.info(
    `enableProxyOnFailAlarm: enableProxyOnFailMaxRetryAttempts:${enableProxyOnFailMaxRetryAttempts}`,
  );
  await setLocalStorageData({
    [LocalStorageKey.EnableProxyOnFailMaxRetryAttempts]: newAttempts,
    [LocalStorageKey.IsNetworkError]: true,
    [LocalStorageKey.isNetworkErrorHandlingInProgress]: true,
  });
  await sendMessageToYoutubeTabs(Actions.NetworkConnectionRetry, undefined);
  return true;
};
