import { Actions } from '@app/actions/shared';
import { browser_api } from '@app/browser_api';
import { getLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { checkShouldSkipCaptcha } from '@background/redirect/utils';
import { replaceTimecodeWithSavedTime } from '@background/urls/replaceTimecodeWithSavedTime';
import { logger } from '@utils/logger';
import { getMetaApiData } from '@utils/metaApiData';

export async function tabsOnActivatedListener(
  activeInfo: browser_api.Tabs.OnActivatedActiveInfoType,
): Promise<void> {
  try {
    await getMetaApiData();

    const { currentState, status, configsBaseUrl } = await getLocalStorageData([
      LocalStorageKey.CurrentState,
      LocalStorageKey.Status,
      LocalStorageKey.ConfigsBaseUrl,
    ]);

    if (currentState !== 'connected') {
      return;
    }

    const tab = await browser_api.tabs.get(activeInfo.tabId);

    if (
      tab.id &&
      tab.url &&
      (tab.url.includes('youtube.com') || tab.url.includes('youtu.be'))
    ) {
      browser_api.tabs.sendMessage(tab.id, {
        action: Actions.UserStatusChanged,
        payload: { status },
      });

      browser_api.tabs.sendMessage(tab.id, {
        action: Actions.ConnectionStateChanged,
        payload: { connectionState: currentState },
      });

      browser_api.tabs.sendMessage(tab.id, {
        action: Actions.ConfigsBaseUrl,
        payload: {
          configsBaseUrl: configsBaseUrl || process.env.CONFIG_BASE_URL_1,
        },
      });
    }

    if (
      tab.id &&
      tab.url &&
      tab.url?.includes('google.com/sorry') &&
      tab.title?.includes('youtube.com/watch')
    ) {
      const shouldSkipCaptcha = await checkShouldSkipCaptcha();

      if (!shouldSkipCaptcha && currentState === 'connected') {
        const newUrl = await replaceTimecodeWithSavedTime(tab.url);

        await browser_api.tabs.update(tab.id, { url: newUrl });
      }
    }
  } catch (error) {
    logger.error('tabsOnActivatedListener error', error);
  }
}
