import { Actions } from '@app/actions/shared';
import { logger } from '@utils/logger';
import { getLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { MessageHandler } from '@app/infrastructure/types';
import { navigateToExtensionPage } from '@background/utils/navigateToExtensionPage';
import { RoutePath } from '@popup/project/youboost/routes/types/RoutePath';

export const openPopupHandler: MessageHandler<Actions.OpenPopup> = async () => {
  logger.info('youboost:Open popup');

  const { userId, isFreePremiumTrialAvailable } = await getLocalStorageData([
    LocalStorageKey.UserId,
    LocalStorageKey.IsFreePremiumTrialAvailable,
  ]);

  if (userId) {
    await navigateToExtensionPage(
      isFreePremiumTrialAvailable ? RoutePath.PremiumInfo : RoutePath.Tariffs,
    );
  }
};
