import { Alarms } from '@app/alarms/shared';
import { browser_api } from '@app/browser_api';
import { setLocalStorageData } from '@app/storage/local/shared';
import { PaymentStatus } from '@app/storage/local/types/persistentTypes';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { logger } from '@utils/logger';

const FREE_USAGE_RESET_INTERVAL_IN_MINUTES =
  process.env.FREE_USAGE_RESET_INTERVAL_IN_MINUTES;
const FREE_USAGE_TIME_IN_SECONDS = process.env.FREE_USAGE_TIME_IN_SECONDS;

export const onStatusChanged = async (status: PaymentStatus) => {
  try {
    logger.info('shared:onStatusChanged', status);

    await browser_api.alarms.clear(Alarms.FreeUsageReset);

    if (status === 'Free') {
      const freeUsageResetIntervalInMinutes = Number(
        FREE_USAGE_RESET_INTERVAL_IN_MINUTES,
      );
      const freeUsageTimeInSeconds = Number(FREE_USAGE_TIME_IN_SECONDS);

      if (
        isNaN(freeUsageResetIntervalInMinutes) ||
        isNaN(freeUsageTimeInSeconds)
      ) {
        return;
      }

      await setLocalStorageData({
        [LocalStorageKey.FreeUsageSecondsLeft]: freeUsageTimeInSeconds,
      });

      browser_api.alarms.create(Alarms.FreeUsageReset, {
        periodInMinutes: freeUsageResetIntervalInMinutes,
      });
    } else if (status === 'Paid') {
      await browser_api.alarms.clear(Alarms.FreeUsage);
    }
  } catch (error) {
    console.error('onStatusChanged error', error);
  }
};
