import { Actions } from '@app/actions/shared';
import { messageDispatcher } from '@app/infrastructure/messageDispatcher';
import { failedVideoOpen } from './failedVideoOpen';
import { saveTime } from './saveTime';
import { changeServerToastClicked } from './changeServerToastClicked';
import { hideAllToasts } from './hideAllToasts';
import { hideAllToastsByType } from './hideAllToastsByType';
import { disableConflictingExtension } from './disableConflictingExtension';

export const registerSharedOnMessageHandlers = () => {
  messageDispatcher.register(Actions.FailedVideoOpen, failedVideoOpen);
  messageDispatcher.register(Actions.SaveTime, saveTime);
  messageDispatcher.register(
    Actions.ChangeServerToastClicked,
    changeServerToastClicked,
  );
  messageDispatcher.register(Actions.HideAllToasts, hideAllToasts);
  messageDispatcher.register(Actions.HideAllToastsByType, hideAllToastsByType);
  messageDispatcher.register(
    Actions.DisableConflictingExtension,
    disableConflictingExtension,
  );
};
