import { MessageHandler } from '@app/infrastructure/types';
import { Actions } from '@app/actions/shared';
import { handleGiftMessage } from '@background/gifts/handleGiftMessage';

export const closeGiftHandler: MessageHandler<Actions.CloseGift> = async (
  message,
) => {
  await handleGiftMessage({
    message,
    popupAction: Actions.ShowRefuseGiftScreen,
  });
};
