import { deactivateDevice } from '@api/premium/deactivateDevice';
import { getDeactivateDeviceApiUrl } from '@api/urls';
import { Actions } from '@app/actions/shared';
import { logger } from '@utils/logger';
import { getMetaApiData } from '@utils/metaApiData';
import { MessageHandler } from '@app/infrastructure/types';

export const deactivateDeviceHandler: MessageHandler<
  Actions.DeactivateDevice
> = async (message) => {
  try {
    logger.info('youboost:Deactivate device');
    const { apiBaseUrl } = await getMetaApiData();
    const response = await deactivateDevice({
      url: getDeactivateDeviceApiUrl(apiBaseUrl),
      body: message.payload,
    });
    if (!response.data.success || !!response.error) {
      throw new Error('Error on deactivate device');
    }
    return { success: true };
  } catch (error) {
    logger.error('deactivateDeviceHandler: error', error);
    return { success: false };
  }
};
