import { messageDispatcher } from '@app/infrastructure/messageDispatcher';
import { Actions } from '@app/actions/shared';
import { giftClickedHandler } from '../giftClickedHandler';
import { closeGiftHandler } from '../closeGiftHandler';
import { refuseGiftHandler } from '../refuseGiftHandler';

export const setupGiftMessageHandler = () => {
  messageDispatcher.register(Actions.GiftClicked, giftClickedHandler);
  messageDispatcher.register(Actions.CloseGift, closeGiftHandler);
  messageDispatcher.register(Actions.RefuseGift, refuseGiftHandler);
};
