import { SubscriptionExpiringToastClickedStatus } from "@app/messages/shared";

/**
 * Map of statuses to their corresponding paths
 * paths should be relative to the extension root in any extension
 * paths should be the same as the RoutePaths in the extensions popup
 */
const SUBSCRIPTION_EXPIRING_POPUP_PATH: Record<SubscriptionExpiringToastClickedStatus, string | null> = {
    'close': null,
    'buy-subscription': '/tariffs',
    'go-to-free': '/free-info-persuasion',
  };
  

  export const getPopupPath = (status: SubscriptionExpiringToastClickedStatus): string | null=> {
    return SUBSCRIPTION_EXPIRING_POPUP_PATH[status];
  };