import { disableProxy } from '@background/network/proxy/proxyControl';
import { setLocalStorageData } from '@app/storage/local/shared';
import { logger } from '@utils/logger';

export const disableProxyAlarm = async () => {
  try {
    await disableProxy();
  } catch (e) {
    logger.error('disableProxy: error', e);
    await setLocalStorageData({ currentState: 'error' });
  }
};
