import { Actions } from '@app/actions/shared';
import { PremiumActions } from '@app/actions/premium';
import { messageDispatcher } from '@app/infrastructure/messageDispatcher';

import { deactivateDeviceHandler } from './deactivateDevice';
import { openPopupRootHandler } from './openPopupRoot';
import { openPopupHandler } from './openPopup';
import { createNewUserHandler } from './createNewUser';
import { openPopupPaymentHandler } from './openPopupPayment';
import { openPopupChangeDeviceHandler } from './openPopupChangeDevice';
import { initAdPremiumBannerHandler } from './initAdPremiumBanner';
import { closeAdPremiumBannerHandler } from './closeAdPremiumBanner';
import { paymentStartedHandler } from './paymentStarted';
import { premiumCanceledHandler } from './premiumCanceled';
import { changeServerManually } from './changeServerManually';
import { turnOffConflictingExtensionWarning } from './turnOffConflictingExtensionWarning';

export const registerYouBoostOnMessageHandlers = () => {
  messageDispatcher.register(Actions.DeactivateDevice, deactivateDeviceHandler);
  messageDispatcher.register(Actions.OpenPopupRoot, openPopupRootHandler);
  messageDispatcher.register(Actions.OpenPopup, openPopupHandler);
  messageDispatcher.register(
    Actions.OpenPopupChangeDevice,
    openPopupChangeDeviceHandler,
  );
  messageDispatcher.register(Actions.CreateNewUser, createNewUserHandler);
  messageDispatcher.register(Actions.OpenPopupPayment, openPopupPaymentHandler);
  messageDispatcher.register(
    PremiumActions.InitPremiumBanner,
    initAdPremiumBannerHandler,
  );
  messageDispatcher.register(
    PremiumActions.ClosePremiumBanner,
    closeAdPremiumBannerHandler,
  );
  messageDispatcher.register(
    PremiumActions.PaymentStarted,
    paymentStartedHandler,
  );
  messageDispatcher.register(
    PremiumActions.PremiumCanceled,
    premiumCanceledHandler,
  );
  messageDispatcher.register(
    Actions.ChangeServerManually,
    changeServerManually,
  );
  messageDispatcher.register(
    Actions.TurnOffConflictingExtensionWarning,
    turnOffConflictingExtensionWarning,
  );
};
