import { Actions } from '@app/actions/shared';
import { logger } from '@utils/logger';
import { MessageHandler } from '@app/infrastructure/types';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { browser_api } from '@app/browser_api';
import { Alarms } from '@app/alarms/shared';
import { setLocalStorageData } from '@app/storage/local/shared';

const AD_BLOCKER_WARNING_PERIOD_IN_MINUTES = process.env
  .AD_BLOCKER_WARNING_PERIOD_IN_MINUTES
  ? parseInt(process.env.AD_BLOCKER_WARNING_PERIOD_IN_MINUTES)
  : 1440;

export const turnOffConflictingExtensionWarning: MessageHandler<
  Actions.TurnOffConflictingExtensionWarning
> = async () => {
  try {
    logger.info('Turn off conflicting extensions warning');
    browser_api.alarms.create(Alarms.ExtensionConflictWarningAdBlocker, {
      periodInMinutes: AD_BLOCKER_WARNING_PERIOD_IN_MINUTES,
    });
    setLocalStorageData({
      [LocalStorageKey.IsExtensionConflictWarningAdBlockerAlarmExisted]: true,
    });
  } catch (error) {
    logger.error('turnOffConflictingExtensionWarning error: ', error);
  }
};
