import { Actions } from '@app/actions/shared';
import { logger } from '@utils/logger';
import { MessageHandler } from '@app/infrastructure/types';
import { navigateToExtensionPage } from '@background/utils/navigateToExtensionPage';

export const changeServerToastClicked: MessageHandler<
  Actions.ChangeServerToastClicked
> = async () => {
  try {
    logger.info('runtimeOnMessageListener:ChangeServerToastClicked');
    await navigateToExtensionPage('/change-server');
  } catch (error) {
    logger.error(
      'runtimeOnMessageListener: error navigating for change server screen',
      error,
    );
  }
};
