import { PremiumAlarms } from '@app/alarms/premium';
import { browser_api } from '@app/browser_api';
import { getLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';

export const initMidRollAlarm = async () => {
  const { metaApiData } = await getLocalStorageData([
    LocalStorageKey.HasPremium,
    LocalStorageKey.MetaApiData,
  ]);

  const { midpointMediaIntervalInMinutes } = metaApiData ?? {};

  if (!midpointMediaIntervalInMinutes) return;

  const midRollAlarm = await browser_api.alarms.get(
    PremiumAlarms.ShowMidpointMedia,
  );

  if (!midRollAlarm) {
    browser_api.alarms.create(PremiumAlarms.ShowMidpointMedia, {
      delayInMinutes: midpointMediaIntervalInMinutes,
      periodInMinutes: midpointMediaIntervalInMinutes,
    });
  }
};
