import {
  getLocalStorageData,
  setLocalStorageData,
} from '@app/storage/local/shared';
import {
  LocalStorageData,
  LocalStorageKey,
} from '@app/storage/local/types/sharedTypes';
import { WebRequest } from 'webextension-polyfill';
import { ERROR_WINDOW_MS } from '@background/network/monitor/constants';

export const addProxyError = async ({
  error,
  url,
}: WebRequest.OnErrorOccurredDetailsType): Promise<number> => {
  const { proxyErrorLog } = await getLocalStorageData([
    LocalStorageKey.ProxyErrorLog,
  ]);

  const now = Date.now();
  const errors: LocalStorageData['proxyErrorLog'] = proxyErrorLog ?? [];

  errors.push({ timestamp: now, error, url });

  const recentErrors = errors.filter(
    (e) => now - e.timestamp < ERROR_WINDOW_MS,
  );

  await setLocalStorageData({
    [LocalStorageKey.ProxyErrorLog]: recentErrors,
  });

  return recentErrors.length;
};
